  /** Answered count vs total — remaining derived for one-line progress hints */
  function fmtAnswerRemainLine(msgKey, answeredCount, totalQuestions) {
    const tot = Math.max(0, Number(totalQuestions) || 0);
    let a = Number(answeredCount);
    if (!Number.isFinite(a)) a = 0;
    a = clamp(Math.floor(a), 0, tot);
    const r = Math.max(0, tot - a);
    return t(msgKey).replace(/\{\{a\}\}/g, String(a)).replace(/\{\{tot\}\}/g, String(tot)).replace(/\{\{r\}\}/g, String(r));
  }

