  function loadState() {
    try {
      const legacyKey = "enmastery:v2";
      let raw = localStorage.getItem(LS) || localStorage.getItem(legacyKey);
      if (!raw) return blankState();
      const p = JSON.parse(raw);
      if (!p.qs || typeof p.qs !== "object") return blankState();
      if (!p.daily || typeof p.daily.day !== "string") p.daily = { day: new Date().toISOString().slice(0, 10), answered: 0 };
      const today = new Date().toISOString().slice(0, 10);
      if (p.daily.day !== today) p.daily = { day: today, answered: 0 };
      if (!Array.isArray(p.studentVocab)) p.studentVocab = [];
      if (!p.session)
        p.session = {
          activeQuiz: QUIZ_ORDER[0],
          activeIdx: 0,
          quizFocusMode: false,
          activeSubjectId: "",
          activeTestSectionId: "",
          quizMode: "normal",
          reviewQuizIds: [],
          lastSessionWrongIds: [],
          mistakePageIds: [],
          mistakePageSubjectId: "",
          mistakePageTitle: "",
        };
      if (!Array.isArray(p.session.lastSessionWrongIds)) p.session.lastSessionWrongIds = [];
      if (!Array.isArray(p.session.mistakePageIds)) p.session.mistakePageIds = [];
      if (typeof p.session.mistakePageSubjectId !== "string") p.session.mistakePageSubjectId = "";
      if (typeof p.session.mistakePageTitle !== "string") p.session.mistakePageTitle = "";
      if (typeof p.session.quizFocusMode !== "boolean") p.session.quizFocusMode = false;
      if (typeof p.session.activeSubjectId !== "string") p.session.activeSubjectId = "";
      if (typeof p.session.activeTestSectionId !== "string") p.session.activeTestSectionId = "";
      if (!["normal", "review", "customQuiz", "mistakeReview"].includes(p.session.quizMode)) p.session.quizMode = "normal";
      if (!Array.isArray(p.session.reviewQuizIds)) p.session.reviewQuizIds = [];
      try {
        delete p.session.quizCompactOpts;
      } catch (_) {}
      if (typeof p.goal !== "number") p.goal = DEFAULT_DAILY_GOAL;
      if (!p.grammar || typeof p.grammar !== "object") p.grammar = { completed: {}, fav: {}, lastLesson: "" };
      if (!p.grammar.completed || typeof p.grammar.completed !== "object") p.grammar.completed = {};
      if (!p.grammar.fav || typeof p.grammar.fav !== "object") p.grammar.fav = {};
      if (typeof p.grammar.lastLesson !== "string") p.grammar.lastLesson = "";
      if (!p.grammar.ui || typeof p.grammar.ui !== "object") p.grammar.ui = {};
      if (!Array.isArray(p.vocabReview)) p.vocabReview = [];
      if (!Array.isArray(p.grammarReview)) p.grammarReview = [];
      if (!p.vocabKnown || typeof p.vocabKnown !== "object") p.vocabKnown = {};
      if (typeof p.vocabShowUnknownOnly !== "boolean") p.vocabShowUnknownOnly = false;
      if (!p.vocabPhaseOpen || typeof p.vocabPhaseOpen !== "object") p.vocabPhaseOpen = {};
      p.v = APP_V;
      localStorage.setItem(LS, JSON.stringify(p));
      try {
        localStorage.removeItem(legacyKey);
      } catch (_) {}
      return p;
    } catch {
      return blankState();
    }
  }

