  function resetActiveQuizProgress() {
    if (state.session.quizMode === "review" && state.session.activeQuiz === REVIEW_SESSION_QUIZ_KEY) {
      const ids = state.session.reviewQuizIds || [];
      for (const id of ids) {
        const s = ensureQs(id);
        s.answered = null;
        s.ok = null;
      }
    } else if (state.session.quizMode === "customQuiz" && isSubjectComprehensiveQuizKey(state.session.activeQuiz)) {
      const compSid = comprehensiveSubjectIdFromKey(state.session.activeQuiz);
      let ids = (state.session.reviewQuizIds || []).filter((id) => questions.some((q) => q.id === id));
      ids = shuffle(ids.length ? ids : questions.filter((q) => String(q.quiz || "").startsWith(`${compSid}|aggregations|`)).map((q) => q.id));
      state.session.reviewQuizIds = ids;
      for (const id of ids) {
        const s = ensureQs(id);
        s.answered = null;
        s.ok = null;
      }
    } else {
      const name = state.session.activeQuiz || QUIZ_ORDER[0];
      const list = byQuiz[name] || [];
      for (const q of list) {
        const s = ensureQs(q.id);
        s.answered = null;
        s.ok = null;
      }
    }
    state.session.activeIdx = 0;
    saveState();
  }

  function normalize(raw) {
    const opts = Array.isArray(raw.options) ? raw.options.map(String) : [];
    let c = raw.correct;
    if (typeof c !== "number") c = parseInt(String(c), 10);
    if (!Number.isFinite(c)) c = 0;
    c = clamp(c, 0, Math.max(0, opts.length - 1));
    return {
      id: String(raw.id),
      quiz: String(raw.quiz || QUIZ_ORDER[0] || ""),
      question: String(raw.question_en ?? raw.question ?? ""),
      options: opts,
      correctIndex: c,
      arabic_explanation: String(raw.arabic_explanation || ""),
      why_answer_ar: String(raw.why_answer_ar || ""),
      grammar_rule_ar: String(raw.grammar_rule_ar || ""),
      vocabulary: String(raw.vocabulary || ""),
      common_mistake_ar: String(raw.common_mistake_ar || ""),
      example_sentence_en: String(raw.example_sentence_en || ""),
      false_explanation: String(raw.false_explanation || ""),
      sentence_translation_ar: String(raw.sentence_translation_ar || raw.translation_ar || ""),
      needs_review: !!raw.needs_review,
      image: String(raw.image || raw.image_url || ""),
    };
  }

  function vocabMap(q) {
    const m = Object.create(null);
    for (const p of q.vocabulary.split("|")) {
      const seg = p.trim();
      if (!seg) continue;
      const eq = seg.split("=");
      if (eq.length >= 2) {
        const w = eq[0].trim().toLowerCase().replace(/^['']|['']$/g, "");
        const ar = eq.slice(1).join("=").trim();
        if (w) m[w] = ar;
      }
    }
    return m;
  }

  function stripOptPrefix(s) {
    return String(s).replace(/^(?:[a-zA-Z]\.\s*|[A-Z]\.\s*)/, "").trim();
  }

  let _vocabCuratedMapCache = null;
  function vocabCuratedMap() {
    if (_vocabCuratedMapCache) return _vocabCuratedMapCache;
    const m = Object.create(null);
    if (typeof VOCAB_BANK !== "undefined" && Array.isArray(VOCAB_BANK)) {
      for (const pair of VOCAB_BANK) {
        if (!pair || pair.length < 2) continue;
        const k = String(pair[0]).toLowerCase().trim();
        if (k) m[k] = pair[1];
      }
    }
    _vocabCuratedMapCache = m;
    return _vocabCuratedMapCache;
  }

  function vocabBlocksForQuestion(q) {
    const map = { ...vocabMap(q), ...EXTRA_HINTS, ...vocabCuratedMap() };
    const bank = [];
    const covered = new Set();
    for (const p of q.vocabulary.split("|")) {
      const seg = p.trim();
      if (!seg) continue;
      const eq = seg.split("=");
      if (eq.length >= 2) {
        const w = eq[0].trim();
        const ar = eq.slice(1).join("=").trim();
        const keyFull = w.toLowerCase().replace(/^['']|['']$/g, "");
        if (!keyFull) continue;
        bank.push({ en: w, ar: ar || t("noTr") });
        for (const part of keyFull.split(/\s+/)) {
          const norm = part.replace(/[^a-z']/gi, "");
          if (norm) covered.add(norm);
        }
      }
    }
    const auto = [];
    const seen = new Set();
    const blob = q.question + " " + q.options.map(stripOptPrefix).join(" ");
    const re = /\b[A-Za-z]+(?:'[A-Za-z]+)?\b/g;
    let mt;
    while ((mt = re.exec(blob))) {
      const w = mt[0];
      const k = w.toLowerCase();
      const norm = k.replace(/[^a-z']/gi, "");
      if (w.length < 2 || !norm || covered.has(norm) || seen.has(k)) continue;
      seen.add(k);
      auto.push({ en: w, ar: map[k] || map[norm] || t("noTr") });
    }
    return { bank, auto };
  }

  function vocSheetHtml(rows) {
    if (!rows.length) return "";
    return rows
      .map(
        (r) =>
          `<div class="voc-row"><span class="voc-en">${esc(r.en)}</span><span class="voc-eq">=</span><span class="voc-ar">${esc(r.ar)}</span></div>`
      )
      .join("");
  }

  function htmlVocabPanels(q) {
    const vb = vocabBlocksForQuestion(q);
    let html = "";
    if (vb.bank.length) {
      html += `<h5>${esc(t("vocFromBank"))}</h5><div class="voc-sheet">${vocSheetHtml(vb.bank)}</div>`;
    }
    if (vb.auto.length) {
      html += `<h5>${esc(t("vocAuto"))}</h5><div class="voc-sheet voc-sheet-auto">${vocSheetHtml(vb.auto)}</div>`;
    }
    if (!html) html = `<div class="empty" style="padding:14px;text-align:center">${esc(t("vocEmpty"))}</div>`;
    return html;
  }

  function translateParagraph(q) {
    if (q.sentence_translation_ar.trim()) return q.sentence_translation_ar.trim();
    const parts = [q.arabic_explanation, q.why_answer_ar].filter(Boolean);
    return parts.join(" ") || (lang === "ar" ? "لا توجد ترجمة جملة مخصصة بعد." : "No dedicated sentence translation yet.");
  }

  function allVocabAgg() {
    const g = new Map();
    const upsert = (row, fromBank) => {
      const k = row.en.toLowerCase();
      const prev = g.get(k);
      const ar = row.ar;
      const good = ar && ar !== t("noTr");
      if (!prev) {
        g.set(k, { en: row.en, ar, isBank: fromBank });
        return;
      }
      const prevGood = prev.ar && prev.ar !== t("noTr");
      if (fromBank && !prev.isBank) {
        g.set(k, { en: row.en, ar: good ? ar : prev.ar, isBank: true });
      } else if (!prevGood && good) {
        g.set(k, { ...prev, ar });
      } else if (fromBank && good && prev.ar !== ar) {
        g.set(k, { ...prev, ar, isBank: true });
      }
    };
    if (typeof VOCAB_BANK !== "undefined" && Array.isArray(VOCAB_BANK)) {
      for (const pair of VOCAB_BANK) {
        if (!pair || pair.length < 2) continue;
        upsert({ en: pair[0], ar: pair[1] }, true);
      }
    }
    for (const q of questions) {
      const vb = vocabBlocksForQuestion(q);
      vb.bank.forEach((row) => upsert(row, true));
      vb.auto.forEach((row) => upsert(row, false));
    }
    const grammarWordRowsFromItem = (it) => {
      const map = { ...EXTRA_HINTS, ...vocabCuratedMap() };
      const blob = [it.question_en || "", ...((it.options || []).map(String))].join(" ");
      const re = /\b[A-Za-z]+(?:'[A-Za-z]+)?\b/g;
      const rows = [];
      const seen = new Set();
      let mt;
      while ((mt = re.exec(blob))) {
        const w = mt[0];
        const k = w.toLowerCase();
        if (seen.has(k)) continue;
        seen.add(k);
        const norm = k.replace(/[^a-z']/gi, "");
        if (w.length < 2 || !norm) continue;
        const ar = map[k] || map[norm] || t("noTr");
        rows.push({ en: w, ar });
      }
      return rows;
    };
    if (Array.isArray(grammarQuizPoolAll)) {
      for (const it of grammarQuizPoolAll) {
        grammarWordRowsFromItem(it).forEach((row) => upsert(row, false));
      }
    }
    try {
      const blend = grammarAuditReadJson("blended-unique-quiz-json");
      const bItems = blend && Array.isArray(blend.items) ? blend.items : [];
      for (const it of bItems) {
        grammarWordRowsFromItem(it).forEach((row) => upsert(row, false));
      }
    } catch (_) {}
    return [...g.values()].sort((a, b) => a.en.localeCompare(b.en));
  }

  /** Map for hover translations on grammar quiz stems + options (merged with bank hints). */
  function grammarQuizWordMap(item) {
    if (!item) return { ...EXTRA_HINTS, ...vocabCuratedMap() };
    const base = { ...EXTRA_HINTS, ...vocabCuratedMap() };
    const out = Object.assign(Object.create(null), base);
    const blob = [item.question_en || "", ...((item.options || []).map(String))].join(" ");
    const re = /\b[A-Za-z]+(?:'[A-Za-z]+)?\b/g;
    let mt;
    while ((mt = re.exec(blob))) {
      const w = mt[0];
      const k = w.toLowerCase();
      const norm = k.replace(/[^a-z']/gi, "");
      if (w.length < 2 || !norm) continue;
      if (!out[k]) {
        const tr = base[k] || base[norm] || t("noTr");
        out[k] = tr;
        if (norm && norm !== k) out[norm] = tr;
      }
    }
    return out;
  }

  function grammarDeepFeedbackHtml(item, pickedIdx) {
    const letters = ["A", "B", "C"];
    const opts = item.options || [];
    let html = `<div class="gram-deep-fb">`;
    html += `<div class="gram-fb-block"><h5 class="gram-fb-h">${esc(t("gramFbUnderstandQ"))}</h5><p class="gram-fb-p">${esc(t("gramFbUnderstandQBody"))}</p></div>`;
    html += `<div class="gram-fb-block"><h5 class="gram-fb-h">${esc(t("gramFbWhyWrong"))}</h5><p class="gram-fb-p">${esc(t("gramFbYouChose"))} <strong dir="ltr">${esc(opts[pickedIdx])}</strong>. ${esc(item.why_ar)}</p></div>`;
    html += `<div class="gram-fb-block"><h5 class="gram-fb-h">${esc(t("gramFbEachOption"))}</h5><ul class="gram-fb-ul">`;
    opts.forEach((op, oi) => {
      const tag =
        oi === item.correct
          ? t("gramFbTagCorrect")
          : oi === pickedIdx
            ? t("gramFbTagYours")
            : t("gramFbTagOther");
      const exp =
        oi === item.correct ? item.why_ar : oi === pickedIdx ? t("gramFbWrongChoiceDetail") : t("gramFbAltWrongDetail");
      html += `<li class="gram-fb-li"><span class="gram-fb-lihead" dir="ltr"><strong>${letters[oi]}</strong> (${esc(tag)}) · ${esc(op)}</span><div class="gram-fb-liexp">${esc(exp)}</div></li>`;
    });
    html += `</ul></div>`;
    html += `<div class="gram-fb-block"><h5 class="gram-fb-h">${esc(t("gramFbRuleReminder"))}</h5><p class="gram-fb-p">${esc(item.rule_ar)}</p></div>`;
    html += `</div>`;
    return html;
  }

  function grammarReviewOfferHtml(lessonId, qi, tag) {
    ensureStateReviews();
    const k = `${lessonId}|${tag}|${qi}`;
    if (state.grammarReview.some((x) => x && x.k === k)) {
      return `<p class="gram-rev-saved" style="margin:12px 0 0;font-size:13px;font-weight:650;color:var(--muted)">${esc(t("reviewSavedGrammar"))}</p>`;
    }
    return `<div class="gram-rev-offer" style="margin-top:12px"><button type="button" class="btn btn-sec gram-rev-add" data-grk="${esc(k)}">${esc(t("reviewSaveBtn"))}</button></div>`;
  }

  function bindGrammarReviewOfferClicks(v) {
    v.querySelectorAll(".gram-rev-add").forEach((btn) => {
      btn.addEventListener("click", () => {
        const k = btn.getAttribute("data-grk");
        if (!k) return;
        ensureStateReviews();
        if (state.grammarReview.some((x) => x && x.k === k)) return;
        state.grammarReview.push({ k });
        saveState();
        toast(t("reviewSavedToast"), "ok");
        render();
      });
    });
  }

  function wireGrammarLessonQuizTokens(v, L, st, qs, hasMultiQuiz) {
    if (hasMultiQuiz) {
      (L.quizStages || []).forEach((stage, si) => {
        const items = stage.quiz || [];
        const stp = st.stages[si];
        const nq = items.length;
        if (!nq) return;
        const qi = clamp(stp.quizPos, 0, nq - 1);
        const item = items[qi];
        if (!item) return;
        const map = grammarQuizWordMap(item);
        const qEl = v.querySelector(`#gqs${si}-qtok-${qi}`);
        if (qEl) tokenizeEn(qEl, item.question_en, map);
        (item.options || []).forEach((op, oi) => {
          const oEl = v.querySelector(`#gqs${si}-opt-${qi}-${oi}`);
          if (oEl) tokenizeEn(oEl, op, map);
        });
      });
      const items = L.quizComprehensive || [];
      const nf = items.length;
      if (nf) {
        const qi = clamp(st.final.quizPos, 0, nf - 1);
        const item = items[qi];
        if (item) {
          const map = grammarQuizWordMap(item);
          const qEl = v.querySelector(`#gqf-qtok-${qi}`);
          if (qEl) tokenizeEn(qEl, item.question_en, map);
          (item.options || []).forEach((op, oi) => {
            const oEl = v.querySelector(`#gqf-opt-${qi}-${oi}`);
            if (oEl) tokenizeEn(oEl, op, map);
          });
        }
      }
    } else if (qs.length) {
      const qi = clamp(st.quizPos, 0, qs.length - 1);
      const item = qs[qi];
      if (!item) return;
      const map = grammarQuizWordMap(item);
      const qEl = v.querySelector(`#gramL-qtok-${qi}`);
      if (qEl) tokenizeEn(qEl, item.question_en, map);
      (item.options || []).forEach((op, oi) => {
        const oEl = v.querySelector(`#gramL-opt-${qi}-${oi}`);
        if (oEl) tokenizeEn(oEl, op, map);
      });
    }
  }

  function wireGrammarExamTokens(root, item, qId, optPrefix) {
    if (!item || !root) return;
    const map = grammarQuizWordMap(item);
    const qt = root.querySelector("#" + qId);
    if (qt) tokenizeEn(qt, item.question_en, map);
    (item.options || []).forEach((op, oi) => {
      const el = root.querySelector("#" + optPrefix + oi);
      if (el) tokenizeEn(el, op, map);
    });
  }

  function readingQuestions() {
    return questions.filter((q) => /Read the text:/i.test(q.question));
  }

  /** Text of the reading passage (before comprehension lines). */
  function readingPassageExtract(q) {
    const full = String(q.question || "");
    const lower = full.toLowerCase();
    const needle = "read the text:";
    const ix = lower.indexOf(needle);
    if (ix < 0) return full.replace(/\s+/g, " ").trim().slice(0, 500);
    let rest = full.slice(ix + needle.length).trim();
    const lines = rest.split(/\n/);
    const kept = [];
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();
      if (!line) {
        if (kept.length > 0) break;
        continue;
      }
      if (/\.{4,}/.test(line)) break;
      if (/^(choose|select|complete|fill in|answer)\b/i.test(line)) break;
      kept.push(line);
      if (kept.join("\n").length > 4000) break;
    }
    const joined = kept.join("\n").trim();
    return joined || rest.replace(/\s+/g, " ").trim().slice(0, 500);
  }

  function readingLessonsDeduped(rq) {
    const seen = new Map();
    for (const q of rq) {
      const body = readingPassageExtract(q);
      const key = body.replace(/\s+/g, " ").trim().slice(0, 1500) || `__id:${q.id}`;
      if (!seen.has(key)) seen.set(key, q);
    }
    return [...seen.values()];
  }

  function readingGroupByQuiz(rq) {
    const order = [];
    const map = Object.create(null);
    for (const q of rq) {
      const qz = q.quiz || "Quiz";
      if (!map[qz]) {
        map[qz] = [];
        order.push(qz);
      }
      map[qz].push(q);
    }
    for (const k of order) {
      map[k].sort((a, b) => a.id.localeCompare(b.id, undefined, { numeric: true }));
    }
    return { order, map };
  }

  function wireReadingCards(container) {
    if (!container) return;
    container.addEventListener("click", (e) => {
      const el = e.target.closest(".read-card");
      if (!el) return;
      const id = el.getAttribute("data-rid");
      if (!id) return;
      const q = questions.find((x) => x.id === id);
      if (!q) return;
      clearReviewQuizMode();
      state.session.activeQuiz = q.quiz;
      const _ix = byQuiz[q.quiz].findIndex((x) => x.id === id);
      state.session.activeIdx = _ix < 0 ? 0 : _ix;
      applySessionFromCourseQuestion(q);
      saveState();
      location.hash = "#/quiz";
    });
  }

  function searchBlob(q) {
    return [q.question, q.arabic_explanation, q.grammar_rule_ar, q.vocabulary].join(" ").toLowerCase();
  }

  function bootQuestions() {
    const arr = Array.isArray(QUESTION_BANK) ? QUESTION_BANK.map(normalize).filter((q) => {
      const qz = String(q.quiz || "");
      return qz.startsWith("integrated-marketing-comms|") || qz.startsWith("customer-experience|");
    }) : [];
    questions = arr;
    byQuiz = {};
    for (const q of questions) {
      if (!byQuiz[q.quiz]) byQuiz[q.quiz] = [];
      byQuiz[q.quiz].push(q);
      ensureQs(q.id);
    }
    for (const k of Object.keys(byQuiz)) {
      byQuiz[k].sort((a, b) => a.id.localeCompare(b.id, undefined, { numeric: true }));
    }
    for (const name of QUIZ_ORDER) {
      if (!byQuiz[name]) byQuiz[name] = [];
    }
  }

  function bootGrammar() {
    grammarLessonsById = {};
    grammarQuizPoolAll = [];
    grammarRuleFirstLessonByKey = {};
    const G = typeof GRAMMAR_DATA !== "undefined" && GRAMMAR_DATA && GRAMMAR_DATA.lessons ? GRAMMAR_DATA : { lessons: {} };
    function grammarLessonQuizItemsFlat(L) {
      const out = [];
      if (Array.isArray(L.quiz)) out.push(...L.quiz);
      if (Array.isArray(L.quizStages)) {
        for (const st of L.quizStages) {
          if (Array.isArray(st.quiz)) out.push(...st.quiz);
        }
      }
      if (Array.isArray(L.quizComprehensive)) out.push(...L.quizComprehensive);
      return out;
    }
    for (const id of Object.keys(G.lessons || {})) {
      const L = G.lessons[id];
      grammarLessonsById[id] = L;
      try {
        const fp = String(L.rule_en || "").toLowerCase().replace(/\s+/g, " ").trim();
        if (fp && !grammarRuleFirstLessonByKey[fp]) grammarRuleFirstLessonByKey[fp] = id;
      } catch (_) {}
      const qs = grammarLessonQuizItemsFlat(L);
      for (let i = 0; i < qs.length; i++) {
        grammarQuizPoolAll.push({
          lessonId: id,
          qi: i,
          question_en: qs[i].question_en,
          options: qs[i].options,
          correct: qs[i].correct,
          why_ar: qs[i].why_ar,
          rule_ar: qs[i].rule_ar,
        });
      }
    }
  }

  function speakEn(line) {
    const s = String(line || "").trim();
    if (!s || !soundOn) return;
    try {
      window.speechSynthesis.cancel();
      const u = new SpeechSynthesisUtterance(s);
      u.lang = "en-US";
      window.speechSynthesis.speak(u);
    } catch (_) {}
  }

  function findGrammarLessonByQuery(raw) {
    const needle = raw.trim().toLowerCase();
    if (!needle) return "";
    for (const id of Object.keys(grammarLessonsById)) {
      const L = grammarLessonsById[id];
      const blob = [id, L.title_en, L.title_ar, ...(L.keywords || [])].join(" ").toLowerCase();
      if (blob.includes(needle)) return id;
    }
    const parts = needle.split(/\s+/).filter(Boolean);
    for (const id of Object.keys(grammarLessonsById)) {
      const L = grammarLessonsById[id];
      const blob = [L.title_en, L.title_ar, ...(L.keywords || []), L.rule_en || "", L.explanation_ar || ""].join(" ").toLowerCase();
      if (parts.length && parts.every((p) => blob.includes(p))) return id;
    }
    return "";
  }

  function grammarEnsureQuizState(lessonId) {
    const L = grammarLessonsById[lessonId];
    if (!L) return null;
    const exCount = (L.examples || []).length;
    const stages = Array.isArray(L.quizStages) ? L.quizStages : null;
    const finalQs = Array.isArray(L.quizComprehensive) ? L.quizComprehensive : null;

    if (stages && stages.length > 0 && finalQs && finalQs.length > 0) {
      if (!grammarLessonQuiz[lessonId] || !grammarLessonQuiz[lessonId].multi) {
        grammarLessonQuiz[lessonId] = {
          multi: true,
          exPos: 0,
          stages: stages.map((s) => ({
            picks: Array((s.quiz || []).length).fill(null),
            quizPos: 0,
          })),
          final: { picks: Array(finalQs.length).fill(null), quizPos: 0 },
        };
      } else {
        const st = grammarLessonQuiz[lessonId];
        const nextStages = stages.map((s, i) => {
          const n = (s.quiz || []).length;
          const prev = st.stages && st.stages[i];
          if (prev && Array.isArray(prev.picks) && prev.picks.length === n) return prev;
          return { picks: Array(n).fill(null), quizPos: 0 };
        });
        st.stages = nextStages;
        if (!st.final || !Array.isArray(st.final.picks) || st.final.picks.length !== finalQs.length) {
          st.final = { picks: Array(finalQs.length).fill(null), quizPos: 0 };
        }
        if (typeof st.exPos !== "number") st.exPos = 0;
        if (exCount > 0) st.exPos = Math.min(st.exPos, exCount - 1);
        else st.exPos = 0;
      }
      return grammarLessonQuiz[lessonId];
    }

    const flatQuiz = Array.isArray(L.quiz) ? L.quiz : [];
    const n = flatQuiz.length;
    if (!grammarLessonQuiz[lessonId] || grammarLessonQuiz[lessonId].multi) {
      grammarLessonQuiz[lessonId] = { picks: Array(n).fill(null), quizPos: 0, exPos: 0 };
    }
    const st = grammarLessonQuiz[lessonId];
    if (typeof st.quizPos !== "number" || st.quizPos < 0) st.quizPos = 0;
    if (typeof st.exPos !== "number" || st.exPos < 0) st.exPos = 0;
    if (!Array.isArray(st.picks) || st.picks.length !== n) {
      st.picks = Array(n).fill(null);
      st.quizPos = 0;
    }
    if (n > 0) st.quizPos = Math.min(st.quizPos, n - 1);
    else st.quizPos = 0;
    if (exCount > 0) st.exPos = Math.min(st.exPos, exCount - 1);
    else st.exPos = 0;
    return st;
  }

  function grammarLessonComplete(lessonId) {
    const L = grammarLessonsById[lessonId];
    if (!L) return false;
    const st = grammarLessonQuiz[lessonId];
    if (!st) return false;
    if (st.multi) {
      const stagesOk =
        Array.isArray(st.stages) &&
        st.stages.every((s) => s.picks.every((x) => x !== null && x !== undefined));
      const finalOk =
        st.final &&
        Array.isArray(st.final.picks) &&
        st.final.picks.every((x) => x !== null && x !== undefined);
      return stagesOk && finalOk;
    }
    if (!Array.isArray(L.quiz)) return false;
    return st.picks.every((x) => x !== null && x !== undefined);
  }

  function grammarMarkLessonDone(lessonId) {
    state.grammar.completed[lessonId] = true;
    saveState();
  }

  function totals() {
    const T = questions.length;
    let ans = 0, ok = 0, bad = 0;
    for (const q of questions) {
      const s = state.qs[q.id];
      if (s && s.answered !== null) {
        ans++;
        if (s.ok) ok++;
        else bad++;
      }
    }
    return { T, ans, ok, bad };
  }

  function pct(a, b) {
    return b ? Math.round((a / b) * 100) : 0;
  }

  function tokenizeEn(el, text, map) {
    el.textContent = "";
    const escapeRe = (s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const cleanKey = (s) => String(s).toLowerCase().trim().replace(/^['']|['']$/g, "");
    const phraseKeys = Object.keys(map || {})
      .map(cleanKey)
      .filter((k) => k && k.includes(" ") && /^[a-z' ]+$/.test(k))
      .sort((a, b) => b.length - a.length);

    const emitWords = (chunk) => {
      const re = /([A-Za-z]+(?:'[A-Za-z]+)?)|([^A-Za-z]+)/g;
      let m;
      while ((m = re.exec(chunk))) {
        if (m[1]) {
          const sp = document.createElement("span");
          sp.className = "w-token";
          sp.textContent = m[1];
          sp.dataset.w = cleanKey(m[1]);
          el.appendChild(sp);
        } else el.appendChild(document.createTextNode(m[2] || ""));
      }
    };

    if (!phraseKeys.length) {
      emitWords(text);
      wireTokens(el, map);
      return;
    }

    // Phrase-aware tokenization (e.g. "air conditioner") using keys from your own vocab data.
    const phraseRe = new RegExp(
      `\\b(?:${phraseKeys.map((k) => escapeRe(k).replace(/\\s+/g, "\\\\s+")).join("|")})\\b`,
      "gi",
    );
    let last = 0;
    let mt;
    while ((mt = phraseRe.exec(text))) {
      const start = mt.index;
      const end = start + mt[0].length;
      if (start > last) emitWords(text.slice(last, start));
      const sp = document.createElement("span");
      sp.className = "w-token";
      sp.textContent = mt[0];
      sp.dataset.w = cleanKey(mt[0]).replace(/\s+/g, " ");
      el.appendChild(sp);
      last = end;
    }
    if (last < text.length) emitWords(text.slice(last));
    wireTokens(el, map);
  }

  function wireTokens(root, map) {
    const tip = $("#wtip");
    let longPress = null;
    const show = (sp, clientX, clientY) => {
      const w = sp.dataset.w || "";
      const curMap = vocabCuratedMap();
      let ar = map[w] || EXTRA_HINTS[w] || curMap[w] || t("noTr");
      tip.style.display = "block";
      tip.innerHTML = `<b>${esc(sp.textContent)}</b><div>${esc(ar)}</div>`;
      const r = sp.getBoundingClientRect();
      let x = r.left + r.width / 2 - tip.offsetWidth / 2;
      let y = r.bottom + 8;
      if (clientX) {
        x = clientX - tip.offsetWidth / 2;
        y = clientY + 12;
      }
      x = clamp(x, 8, innerWidth - tip.offsetWidth - 8);
      y = clamp(y, 8, innerHeight - tip.offsetHeight - 8);
      tip.style.left = x + "px";
      tip.style.top = y + "px";
    };
    const isTouch = "ontouchstart" in window;
    root.querySelectorAll(".w-token").forEach((sp) => {
      sp.addEventListener("mouseenter", () => {
        if (isTouch) return;
        show(sp);
      });
      sp.addEventListener("mouseleave", () => {
        if (isTouch) return;
        tip.style.display = "none";
      });
      sp.addEventListener("touchstart", (e) => {
        clearTimeout(longPress);
        const touch = e.touches[0];
        longPress = setTimeout(() => {
          show(sp, touch.clientX, touch.clientY);
          navigator.vibrate?.(12);
        }, 480);
      }, { passive: true });
      sp.addEventListener("touchend", () => clearTimeout(longPress));
      sp.addEventListener("touchmove", () => {
        clearTimeout(longPress);
        tip.style.display = "none";
      });
    });
  }

  function parseRoute() {
    const raw = (location.hash || "#/").replace(/^#\/?/, "");
    const parts = raw.split("/").filter(Boolean);

    testsSubjectId = "";
    testsSubjectSectionId = "";
    testsSubjectMode = "";
    reviewSubjectId = "";
    studySubjectId = "";
    falseSubjectId = "";
    mistakePageSubjectId = "";

    /** `#/` أو بدون مسار → الشاشة الرئيسية مع التحية (صباح/مساء) */
    if (!parts.length) {
      route = "home";
      return;
    }

    const top = parts[0];

    if (top === "tests") {
      if (!parts[1]) {
        try {
          const want = `${location.pathname}${location.search}#/`;
          if (location.hash !== "#/" && location.hash !== "#") {
            history.replaceState(history.state, "", want);
          }
        } catch (_) {}
        route = "home";
        return;
      }
      route = "tests";
      testsSubjectId = decodeURIComponent(parts[1]);
      if (parts[2]) {
        const sec = decodeURIComponent(parts[2]);
        if (SUBJECT_TEST_SECTION_IDS.includes(sec)) testsSubjectSectionId = sec;
      }
      if (parts[3]) testsSubjectMode = decodeURIComponent(parts[3]);
      return;
    }

    if (top === "quiz") {
      route = "quiz";
      if (parts[1]) state.session.activeQuiz = decodeURIComponent(parts[1]);
      return;
    }

    if (top === "study") {
      route = "study";
      if (parts[1]) studySubjectId = decodeURIComponent(parts[1]);
      return;
    }



    if (top === "false-answers") {
      route = "false-answers";
      if (parts[1]) falseSubjectId = decodeURIComponent(parts[1]);
      return;
    }


    if (top === "quiz-mistakes") {
      route = "quiz-mistakes";
      if (parts[1]) mistakePageSubjectId = decodeURIComponent(parts[1]);
      return;
    }

    if (top === "review") {
      route = "review";
      if (parts[1]) reviewSubjectId = decodeURIComponent(parts[1]);
      return;
    }

    const ok = ["tests", "quiz", "quiz-mistakes", "review", "study", "false-answers"];
    route = ok.includes(top) ? top : "home";
  }

