  function getEvtEl(e) {
    const t = e && e.target;
    // Some browsers may target Text nodes or SVG sub-elements.
    if (t && t.nodeType === 1) return t; // Element
    if (t && t.parentElement) return t.parentElement;
    return null;
  }

  // Global in-app navigation handler.
  // Capture phase so it still works even if some UI stops bubbling.
  // Use pointerup to be reliable on mobile.
  const onNav = (e) => {
    const el = getEvtEl(e);
    if (!el || !el.closest) return;

    const backEl = el.closest("[data-back]");
    const a = el.closest("a[href]");
    const h = (backEl && backEl.getAttribute("data-back")) || (a && a.getAttribute("href")) || "";
    if (!h) return;
    if (!navToHashMaybe(h)) return;
    e.preventDefault?.();
  };
  document.addEventListener("pointerup", onNav, true);
  document.addEventListener("click", onNav, true);

