  let imcCelebrationTimer = null;
  function showImcCompletionCelebration(nextHash) {
    if (imcCelebrationTimer) {
      clearTimeout(imcCelebrationTimer);
      imcCelebrationTimer = null;
    }
    document.querySelectorAll(".imc-celebration-overlay,.imc-canvas-celebration").forEach((el) => el.remove());

    const overlay = document.createElement("div");
    overlay.className = "imc-canvas-celebration";
    overlay.setAttribute("role", "status");
    overlay.setAttribute("aria-live", "polite");
    overlay.innerHTML = `<canvas aria-hidden="true"></canvas><div class="imc-celebration-title">تم بحمد الله</div>`;
    document.body.appendChild(overlay);

    const canvas = overlay.querySelector("canvas");
    const ctx = canvas && canvas.getContext ? canvas.getContext("2d") : null;
    if (!ctx) {
      imcCelebrationTimer = setTimeout(() => {
        overlay.remove();
        imcCelebrationTimer = null;
        location.hash = nextHash || "#/tests/integrated-marketing-comms";
      }, 900);
      return;
    }

    const title = overlay.querySelector(".imc-celebration-title");
    const colors = ["#d4af37", "#e8c547", "#22c55e", "#f8fafc", "#f59e0b", "#38bdf8", "#fb7185", "#a7f3d0", "#ffffff"];
    let W = 0, H = 0, DPR = 1, cx = 0, cy = 0;
    const isMobile = Math.min(window.innerWidth || 390, (window.screen && window.screen.width) || 390) <= 720;
    const count = isMobile ? 260 : 320;
    const pieces = [];
    const startTime = performance.now();

    function resizeCanvas() {
      DPR = Math.min(window.devicePixelRatio || 1, 2);
      W = Math.max(window.innerWidth || document.documentElement.clientWidth || 390, 320);
      H = Math.max(window.innerHeight || document.documentElement.clientHeight || 720, 520);
      canvas.width = Math.floor(W * DPR);
      canvas.height = Math.floor(H * DPR);
      canvas.style.width = W + "px";
      canvas.style.height = H + "px";
      ctx.setTransform(DPR, 0, 0, DPR, 0, 0);
      cx = W / 2;
      cy = H / 2;
    }
    resizeCanvas();

    function heartPoint(t, scale) {
      return {
        x: 16 * Math.pow(Math.sin(t), 3) * scale,
        y: -(13 * Math.cos(t) - 5 * Math.cos(2*t) - 2 * Math.cos(3*t) - Math.cos(4*t)) * scale,
      };
    }
    function edgeStart(i) {
      const edge = i % 4;
      if (edge === 0) return { x: -90 - Math.random() * W * .35, y: Math.random() * H };
      if (edge === 1) return { x: W + 90 + Math.random() * W * .35, y: Math.random() * H };
      if (edge === 2) return { x: Math.random() * W, y: -90 - Math.random() * H * .25 };
      return { x: Math.random() * W, y: H + 90 + Math.random() * H * .25 };
    }
    function lerp(a, b, p) { return a + (b - a) * p; }
    function ease(p) { return 1 - Math.pow(1 - Math.max(0, Math.min(1, p)), 3); }

    for (let i = 0; i < count; i++) {
      const start = edgeStart(i);
      const hp = heartPoint((Math.PI * 2 * i) / count, isMobile ? Math.min(W / 39, 9.7) : 11.4);
      const angle = Math.random() * Math.PI * 2;
      const push = (isMobile ? 135 : 170) + Math.random() * (isMobile ? 190 : 230);
      pieces.push({
        sx: start.x, sy: start.y,
        hx: cx + hp.x + (Math.random() - .5) * 7,
        hy: cy + hp.y + (Math.random() - .5) * 7,
        bx: cx + Math.cos(angle) * push,
        by: cy + Math.sin(angle) * push,
        fx: Math.random() * W,
        fy: Math.random() * H,
        ex: cx + (Math.random() - .5) * W * 1.45,
        ey: -90 - Math.random() * H * .55,
        w: (isMobile ? 6 : 7) + Math.random() * 5,
        h: (isMobile ? 9 : 11) + Math.random() * 10,
        color: colors[i % colors.length],
        rot: Math.random() * Math.PI * 2,
        speed: .02 + Math.random() * .04,
        delay: Math.random() * 230,
        round: Math.random() > .5,
      });
    }

    function drawPiece(p, x, y, r, alpha, scale) {
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.translate(x, y);
      ctx.rotate(r);
      ctx.fillStyle = p.color;
      const ww = p.w * scale;
      const hh = p.h * scale;
      if (p.round) {
        ctx.beginPath();
        ctx.ellipse(0, 0, ww / 2, hh / 2, 0, 0, Math.PI * 2);
        ctx.fill();
      } else {
        ctx.fillRect(-ww / 2, -hh / 2, ww, hh);
      }
      ctx.restore();
    }

    function frame(now) {
      const t = now - startTime;
      ctx.clearRect(0, 0, W, H);
      if (title) title.style.opacity = String(t < 400 ? t / 400 : t > 4700 ? Math.max(0, 1 - (t - 4700) / 800) : 1);
      for (const p of pieces) {
        const tt = Math.max(0, t - p.delay);
        let x, y, alpha = 1, scale = 1, rot = p.rot + tt * p.speed;
        if (tt < 1500) {
          const e = ease(tt / 1500);
          x = lerp(p.sx, p.hx, e);
          y = lerp(p.sy, p.hy, e);
          alpha = Math.min(1, tt / 280);
          scale = .7 + .3 * e;
        } else if (tt < 2550) {
          x = p.hx;
          y = p.hy;
        } else if (tt < 3350) {
          const e = ease((tt - 2550) / 800);
          x = lerp(p.hx, p.bx, e);
          y = lerp(p.hy, p.by, e);
          scale = 1 + .4 * e;
        } else if (tt < 4200) {
          const e = ease((tt - 3350) / 850);
          x = lerp(p.bx, p.fx, e);
          y = lerp(p.by, p.fy, e);
          scale = 1.1 - .1 * e;
        } else {
          const e = ease((tt - 4200) / 1050);
          x = lerp(p.fx, p.ex, e);
          y = lerp(p.fy, p.ey, e);
          alpha = Math.max(0, 1 - e);
          scale = .95 - .35 * e;
        }
        drawPiece(p, x, y, rot, alpha, scale);
      }
      if (t < 5600) requestAnimationFrame(frame);
    }
    requestAnimationFrame(frame);

    imcCelebrationTimer = setTimeout(() => {
      overlay.remove();
      imcCelebrationTimer = null;
      location.hash = nextHash || "#/tests/integrated-marketing-comms";
    }, 5700);
  }


  /** الصفحة الرئيسية الوحيدة — اللوجو و #/ وكل مسار «الرئيسية» يستدعيها بنفس الهيكل والأنيميشن */
