  function renderGrammarLesson(lessonId) {
    const L = grammarLessonsById[lessonId];
    const v = $("#view");
    if (!L) {
      v.innerHTML = `${backBar("#/grammar/lessons")}<div class="panel"><p>${esc(t("gramEmptyCat"))}</p></div>`;
      $("[data-back]")?.addEventListener("click", () => (location.hash = "#/grammar/lessons"));
      return;
    }

    state.grammar.lastLesson = lessonId;
    saveState();

    const cat = L.categoryId || "";
    const back = cat ? "#/grammar/cat/" + encodeURIComponent(cat) : "#/grammar/lessons";

    const G = typeof GRAMMAR_DATA !== "undefined" ? GRAMMAR_DATA : { categories: [] };
    const catObj = (G.categories || []).find((c) => c.id === cat);
    const catTitleCrumb =
      catObj &&
      (lang === "en" && catObj.title_en && String(catObj.title_en).trim()
        ? String(catObj.title_en).trim()
        : catObj.title_ar || "");
    const lessonTitleCrumb =
      lang === "en" && L.title_en && String(L.title_en).trim()
        ? String(L.title_en).trim()
        : L.title_ar || "";
    const breadcrumbHtml = `
      <nav class="gram-breadcrumb" aria-label="${esc(t("grammarTitle"))}">
        <a href="#/grammar/lessons">${esc(t("gramLandingGrammarCard"))}</a>
        <span class="gram-bc-sep" aria-hidden="true">›</span>
        ${
          catObj && catTitleCrumb
            ? `<a href="#/grammar/cat/${encodeURIComponent(catObj.id)}">${esc(catTitleCrumb)}</a>
        <span class="gram-bc-sep" aria-hidden="true">›</span>`
            : ""
        }
        <span aria-current="page">${esc(lessonTitleCrumb)}</span>
      </nav>`;
    const hasText = (s) => !!String(s || "").trim();
    const topicInfer = () => {
      const blob = [L.title_en, L.title_ar, L.rule_en, L.explanation_ar, L.keywords ? L.keywords.join(" ") : ""]
        .join(" ")
        .toLowerCase();
      const TOPICS = [
        "past simple",
        "present simple",
        "present continuous",
        "present perfect",
        "articles",
        "prepositions",
        "there is",
        "there are",
        "comparative",
        "superlative",
        "countable",
        "uncountable",
        "going to",
        "will",
        "possessive adjectives",
        "pronouns",
      ];
      for (const k of TOPICS) {
        if (blob.includes(k)) return { en: k, ar: EXTRA_HINTS[k] || "" };
      }
      return { en: "", ar: "" };
    };
    const topic = topicInfer();
    const contextExample = () => {
      const ex = Array.isArray(L.examples) && L.examples.length ? L.examples[0] : null;
      if (ex && (ex.en || ex.ar)) return ex;
      const qx = Array.isArray(L.quiz) && L.quiz.length ? L.quiz[0] : null;
      if (qx && qx.question_en) return { en: qx.question_en, ar: "" };
      return null;
    };
    const ctx = contextExample();
    const conceptText = String(L.explanation_ar || "").trim();
    const explainBlock = conceptText
      ? `<div class="gram-lesson-lead-card">
        <span class="gram-lesson-lead-kicker">${esc(t("gramLessonExplainLabel"))}</span>
        ${grammarScopeDescHtml(conceptText)}
        ${
          ctx && ctx.en
            ? `<div class="panel" style="margin-top:12px;padding:12px 14px;border-radius:12px;background:color-mix(in srgb, var(--surface) 78%, transparent);border:1px dashed color-mix(in srgb, var(--border) 75%, transparent)">
              <div style="font-size:11px;letter-spacing:.08em;text-transform:uppercase;color:var(--gold);font-weight:900;margin-bottom:6px">Context example</div>
              <div class="en-text" dir="ltr">${esc(ctx.en)}</div>
              ${ctx.ar ? `<div class="ar-text" style="margin-top:6px">${esc(ctx.ar)}</div>` : ""}
            </div>`
            : ""
        }
      </div>`
      : "";

    const isIrregular = lessonId === "past-simple-irregular-verbs";
    const irrNormBaseKey = (s) =>
      String(s || "")
        .trim()
        .toLowerCase()
        .replace(/\s*\/\s*/g, "/")
        .replace(/\s+/g, " ");
    const irrMasterByBase = (() => {
      const m = new Map();
      for (const x of IRR_APPROVED_MASTER) {
        const k = irrNormBaseKey(x.base);
        if (k) m.set(k, x);
      }
      return m;
    })();
    const irrLookupRow = (row) => {
      if (!Array.isArray(row) || row.length < 2) return null;
      const v1 = irrNormBaseKey(row[1]);
      return irrMasterByBase.get(v1) || null;
    };
    const irrHeaderAr = (h) => {
      const s = String(h || "").trim();
      if (s.includes("المصدر") && s.includes("V1")) return "المضارع (الشكل الأول)";
      if (s.includes("الماضي") && s.includes("V2")) return "الماضي";
      if (s.includes("المشار إليه") || (s.includes("V3") && s.includes("المشار"))) return "التصريف الثالث";
      return s;
    };

    function grammarLessonTableBlock(T) {
      if (!T || !T.headers || !T.rows) return "";
      const titleRaw =
        lang === "en" && T.title_en && String(T.title_en).trim()
          ? String(T.title_en).trim()
          : T.title_ar || T.title_en || "";
      const cap = titleRaw
        ? `<h4 class="gram-table-caption" style="margin:14px 0 8px;font-size:15px;font-weight:700;color:var(--text)">${esc(titleRaw)}</h4>`
        : "";
      const thead =
        isIrregular && Array.isArray(T.headers)
          ? `<thead><tr>${T.headers.map((h) => `<th dir="rtl" style="font-family:var(--font);font-weight:800">${esc(irrHeaderAr(h))}</th>`).join("")}</tr></thead>`
          : `<thead><tr>${T.headers.map((h) => `<th>${esc(h)}</th>`).join("")}</tr></thead>`;
      const tbodyIrregular = () =>
        `<tbody>${T.rows
          .map((r) => {
            const irr = irrLookupRow(r);
            const cells = r.map((c, colIdx) => {
              const raw = String(c ?? "").trim();
              if (colIdx === 0) return `<td dir="rtl" style="vertical-align:top">${esc(raw)}</td>`;
              let arHint = "";
              if (irr) {
                if (colIdx === 1) arHint = String(irr.meaning || "").trim();
                else if (colIdx === 2) arHint = String(irr.past_ar || "").trim();
                else if (colIdx === 3) arHint = String(irr.v3_ar || "").trim();
              }
              const sub = arHint
                ? `<div dir="rtl" style="margin-top:5px"><span class="chip" style="font-size:12px;opacity:.92">${esc(arHint)}</span></div>`
                : "";
              return `<td dir="ltr" style="font-family:var(--irr-en);font-weight:750;vertical-align:top">${esc(raw)}${sub}</td>`;
            });
            return `<tr>${cells.join("")}</tr>`;
          })
          .join("")}</tbody>`;
      const tbodyDefault = () =>
        `<tbody>${T.rows.map((r) => `<tr>${r.map((c) => `<td>${esc(c)}</td>`).join("")}</tr>`).join("")}</tbody>`;
      const inner = `<table class="gram-table gram-table--irr-source">${thead}${isIrregular ? tbodyIrregular() : tbodyDefault()}</table>`;
      return cap + `<div class="table-responsive" role="region" aria-label="${esc(titleRaw || t("gramSecTable"))}">${inner}</div>`;
    }
    const tbl =
      Array.isArray(L.tables) && L.tables.length > 0
        ? L.tables.map(grammarLessonTableBlock).join("")
        : grammarLessonTableBlock(L.table);
    const hasTable = !!String(tbl || "").trim();
    const hasRule = hasText(L.rule_en);

    const hasMultiQuiz =
      Array.isArray(L.quizStages) &&
      L.quizStages.length > 0 &&
      Array.isArray(L.quizComprehensive) &&
      L.quizComprehensive.length > 0;
    grammarEnsureQuizState(lessonId);
    if (grammarLessonComplete(lessonId)) grammarMarkLessonDone(lessonId);

    const exList = L.examples || [];
    const qs = hasMultiQuiz ? [] : Array.isArray(L.quiz) ? L.quiz : [];
    const hasExamples = Array.isArray(exList) && exList.length > 0;
    const hasQuiz = !!(hasMultiQuiz || (Array.isArray(qs) && qs.length > 0));

    const st = grammarLessonQuiz[lessonId];
    const favOn = !!state.grammar.fav[lessonId];
    const doneOn = !!state.grammar.completed[lessonId];

    const ei = exList.length ? Math.min(st.exPos, exList.length - 1) : 0;
    const exampleBody =
      exList.length > 0
        ? `<div class="gram-ex" data-ex-i="${ei}">
        <div class="en">${esc(exList[ei].en)}</div>
        <div class="ar">${esc(exList[ei].ar)}</div>
        <button type="button" class="gram-speak" data-speak="${esc(exList[ei].en)}">🔊 Listen</button>
      </div>`
        : `<p class="empty">${esc(t("quizEmptySoon"))}</p>`;

    const exNav =
      exList.length > 1
        ? `<div class="gram-step-nav">
        <span class="gram-step-meta">${esc(grammarFmtProgress("gramExProgress", ei + 1, exList.length))}</span>
        <div class="gram-step-btns">
          <button type="button" class="btn" id="gramExPrev" ${ei <= 0 ? "disabled" : ""}>${esc(t("prev"))}</button>
          <button type="button" class="btn btn-primary" id="gramExNext" ${ei >= exList.length - 1 ? "disabled" : ""}>${esc(t("next"))}</button>
        </div>
      </div>`
        : exList.length === 1
          ? `<div class="gram-step-meta" style="margin-bottom:10px">${esc(grammarFmtProgress("gramExProgress", 1, 1))}</div>`
          : "";

    function grammarLessonQuizPanel(items, stPart, idsPrefix, dataGramQuiz) {
      const nq = (items || []).length;
      if (!nq) return `<p class="empty">${esc(t("emptyQuiz"))}</p>`;
      const qi = clamp(stPart.quizPos, 0, nq - 1);
      stPart.quizPos = qi;
      const item = items[qi];
      const picked = stPart.picks[qi];
      const locked = picked !== null && picked !== undefined;
      const ok = locked && picked === item.correct;
      const deepWrong = locked && !ok ? grammarDeepFeedbackHtml(item, picked) : "";
      const gramRevOffer = locked && !ok ? grammarReviewOfferHtml(lessonId, qi, String(dataGramQuiz)) : "";
      const nQuizAnswered = stPart.picks.filter((x) => x !== null && x !== undefined).length;
      const letters = ["A", "B", "C"];
      const opts = item.options
        .map((op, oi) => {
          let cls = "opt";
          if (locked) cls += oi === item.correct ? " correct" : picked === oi ? " wrong" : "";
          return `<button type="button" class="${cls}" data-qix="${qi}" data-oix="${oi}" data-gram-quiz="${esc(
            dataGramQuiz
          )}" ${locked ? "disabled" : ""}><span class="L">${letters[oi]}</span><span class="txt gram-opt-tok" dir="ltr" id="${idsPrefix}-opt-${qi}-${oi}"></span></button>`;
        })
        .join("");
      const fbCls = !locked ? "" : ok ? "ok" : "bad";
      const fbOn = locked ? "on" : "";
      return `
        <div class="gram-step-wrap">
          <div class="gram-step-nav">
            <span class="gram-step-meta">${esc(grammarFmtProgress("gramQuizProgress", qi + 1, nq))}</span>
            <div class="gram-step-btns">
              <button type="button" class="btn" id="${idsPrefix}-quiz-prev" ${qi <= 0 ? "disabled" : ""}>${esc(t("prev"))}</button>
              <button type="button" class="btn btn-primary" id="${idsPrefix}-quiz-next" ${qi >= nq - 1 ? "disabled" : ""}>${esc(t("next"))}</button>
            </div>
          </div>
          <p class="gram-answer-remain">${esc(fmtAnswerRemainLine("quizAnswerRemainLine", nQuizAnswered, nq))}</p>
          <div class="gram-qblock" data-qix="${qi}">
            <div class="q-label gram-q-line" dir="ltr"><span class="gram-q-num">${qi + 1}.</span> <span class="gram-q-tokens-host" id="${idsPrefix}-qtok-${qi}"></span></div>
            <div class="opts">${opts}</div>
            <div class="gram-feedback ${fbCls} ${fbOn}" id="${idsPrefix}-gf-${qi}">
              <strong>${ok ? esc(t("gramCorrect")) : esc(t("gramWrong"))}</strong> —
              ${esc(t("gramWhy"))}: ${esc(item.why_ar)}<br/>
              ${esc(t("gramUsedRule"))}: ${esc(item.rule_ar)}
              ${deepWrong}
              ${gramRevOffer}
            </div>
          </div>
        </div>`;
    }

    let quizHtml = "";
    let quizSection = "";
    if (hasMultiQuiz) {
      const mst = st;
      if (!mst.ui || typeof mst.ui !== "object") mst.ui = { mode: "stage", stage: 0 };
      if (mst.ui.mode !== "stage" && mst.ui.mode !== "final") mst.ui.mode = "stage";
      if (typeof mst.ui.stage !== "number") mst.ui.stage = 0;
      mst.ui.stage = clamp(mst.ui.stage, 0, Math.max(0, (L.quizStages || []).length - 1));

      const stageChips = (L.quizStages || [])
        .map((stage, si) => {
          const title =
            lang === "en" && stage.title_en && String(stage.title_en).trim()
              ? String(stage.title_en).trim()
              : stage.title_ar || "";
          const on = mst.ui.mode === "stage" && mst.ui.stage === si;
          return `<button type="button" class="pill ${on ? "on" : ""}" data-gqtab="stage" data-stage="${si}">${esc(
            title || ("Stage " + (si + 1)),
          )}</button>`;
        })
        .join("");
      const finalChip = `<button type="button" class="pill ${mst.ui.mode === "final" ? "on" : ""}" data-gqtab="final">${esc(
        t("gramQuizComprehensiveTitle"),
      )}</button>`;

      const inner =
        mst.ui.mode === "final"
          ? grammarLessonQuizPanel(L.quizComprehensive, mst.final, `gqf`, `final`)
          : grammarLessonQuizPanel((L.quizStages[mst.ui.stage] || {}).quiz || [], mst.stages[mst.ui.stage], `gqs${mst.ui.stage}`, `stage:${mst.ui.stage}`);

      quizSection = `
        <div class="gram-quiz-stages-wrap" style="margin-bottom:10px">
          <p style="margin:0 0 10px;font-size:13px;color:var(--muted);line-height:1.55;font-weight:650">${esc(t("gramQuizStagesLead"))}</p>
          <div class="pillrow" style="gap:10px;flex-wrap:wrap">${stageChips}${finalChip}</div>
        </div>
        <div class="gram-quiz-block">${inner}</div>
      `;
    } else if (qs.length === 0) {
      quizSection = `<p class="empty">${esc(t("emptyQuiz"))}</p>`;
    } else {
      const qi = st.quizPos;
      const item = qs[qi];
      const picked = st.picks[qi];
      const locked = picked !== null && picked !== undefined;
      const ok = locked && picked === item.correct;
      const nQuizAnswered = st.picks.filter((x) => x !== null && x !== undefined).length;
      const letters = ["A", "B", "C"];
      const opts = item.options
        .map((op, oi) => {
          let cls = "opt";
          if (locked) cls += oi === item.correct ? " correct" : picked === oi ? " wrong" : "";
          return `<button type="button" class="${cls}" data-qix="${qi}" data-oix="${oi}" data-gram-quiz="legacy" ${locked ? "disabled" : ""}><span class="L">${letters[oi]}</span><span class="txt gram-opt-tok" dir="ltr" id="gramL-opt-${qi}-${oi}"></span></button>`;
        })
        .join("");
      const deepWrong = locked && !ok ? grammarDeepFeedbackHtml(item, picked) : "";
      const gramRevOffer = locked && !ok ? grammarReviewOfferHtml(lessonId, qi, "legacy") : "";
      const fbCls = !locked ? "" : ok ? "ok" : "bad";
      const fbOn = locked ? "on" : "";
      quizHtml = `
        <div class="gram-step-wrap">
          <div class="gram-step-nav">
            <span class="gram-step-meta">${esc(grammarFmtProgress("gramQuizProgress", qi + 1, qs.length))}</span>
            <div class="gram-step-btns">
              <button type="button" class="btn" id="gramQuizPrev" ${qi <= 0 ? "disabled" : ""}>${esc(t("prev"))}</button>
              <button type="button" class="btn btn-primary" id="gramQuizNext" ${qi >= qs.length - 1 ? "disabled" : ""}>${esc(t("next"))}</button>
            </div>
          </div>
          <p class="gram-answer-remain">${esc(fmtAnswerRemainLine("quizAnswerRemainLine", nQuizAnswered, qs.length))}</p>
          <div class="gram-qblock" data-qix="${qi}">
            <div class="q-label gram-q-line" dir="ltr"><span class="gram-q-num">${qi + 1}.</span> <span class="gram-q-tokens-host" id="gramL-qtok-${qi}"></span></div>
            <div class="opts">${opts}</div>
            <div class="gram-feedback ${fbCls} ${fbOn}" id="gf-${qi}">
              <strong>${ok ? esc(t("gramCorrect")) : esc(t("gramWrong"))}</strong> —
              ${esc(t("gramWhy"))}: ${esc(item.why_ar)}<br/>
              ${esc(t("gramUsedRule"))}: ${esc(item.rule_ar)}
              ${deepWrong}
              ${gramRevOffer}
            </div>
          </div>
        </div>`;
      quizSection = `${quizHtml}`;
    }

    // Prevent repetition: if rule_en already appeared in a previous lesson, show a reference instead of repeating.
    const ruleFp = String(L.rule_en || "").toLowerCase().replace(/\s+/g, " ").trim();
    const firstRuleLesson = ruleFp ? grammarRuleFirstLessonByKey[ruleFp] : "";
    const isRuleDuplicate = !!(firstRuleLesson && firstRuleLesson !== lessonId);

    const warnMark = (why) => `<span class="warn" title="${esc(why)}">❗</span>`;
    const suspiciousText = (s) => {
      const x = String(s || "").trim();
      if (!x) return true;
      if (x === "—" || x === "-" || x.toLowerCase().includes("todo")) return true;
      return false;
    };
    const ruleWarn = hasRule && suspiciousText(L.rule_en) ? "نص القاعدة غير واضح/ناقص" : "";

    const rulePanel = hasRule
      ? `<div class="panel gram-sec glass-card">
        <h3 class="gram-sec-title">${esc("Snap explanation")}
          ${ruleWarn ? warnMark(ruleWarn) : ""}
        </h3>
        ${
          isRuleDuplicate
            ? `<p class="lead" style="margin:0 0 10px;font-size:13px;font-weight:700;color:var(--muted)">تم شرح هذه القاعدة مسبقًا في درس آخر. يمكنك فتحه بدل إعادة القراءة هنا.</p>
               <a class="btn btn-sec" href="#/grammar/lesson/${encodeURIComponent(firstRuleLesson)}" style="text-decoration:none;display:inline-flex;align-items:center;justify-content:center">${esc(
                 (grammarLessonsById[firstRuleLesson] && (lang === "ar" ? grammarLessonsById[firstRuleLesson].title_ar : grammarLessonsById[firstRuleLesson].title_en)) ||
                   t("gramOpen"),
               )}</a>`
            : `<div class="gram-rule-sec-inner">
              <div class="gram-rule-hint-wrap">
                <p class="gram-rule-hint">${esc(t("gramRuleEnHint"))}</p>
              </div>
              <div class="gram-rule-stack">${grammarFormatRuleEn(L.rule_en)}</div>
            </div>`
        }
      </div>`
      : "";

    const tableWarn = hasTable && suspiciousText(tbl) ? "محتوى الجدول غير مكتمل/غير قابل للقراءة" : "";
    const tablePanel = hasTable
      ? `<div class="panel gram-sec glass-card">
        <h3 class="gram-sec-title">${esc("Rules in action")}
          ${tableWarn ? warnMark(tableWarn) : ""}
        </h3>
        <p class="gram-sec-kicker">${esc(t("gramSecTable"))}</p>
        ${tbl}
      </div>`
      : "";

    // We only show lesson-specific content inside lessons (no global filler).
    const showPronounSection = false;

    const examplesPanel = hasExamples
      ? `<div class="panel gram-sec gram-examples-panel glass-card">
        <h3 class="gram-sec-title">${esc("Rules in action")}</h3>
        <p class="gram-sec-kicker">${esc(t("gramSecExamples"))}</p>
        <div class="gram-sec-body">
          <div class="gram-step-wrap">${exNav}${exampleBody}</div>
        </div>
      </div>`
      : "";

    const notesHas = hasText(L.notes_ar) || hasText(L.mistakes_ar) || hasText(L.compare_ar);
    const notesPanelInner = (() => {
      if (!notesHas) return "";
      const blocks = [];
      if (hasText(L.notes_ar)) blocks.push(`<div class="gram-notes-lead-wrap">${grammarArabicFlowHtml(L.notes_ar)}</div>`);
      if (hasText(L.mistakes_ar))
        blocks.push(`<div class="gram-subsec"><h5>${esc(t("gramMistakes"))}</h5>${grammarArabicFlowHtml(L.mistakes_ar)}</div>`);
      if (hasText(L.compare_ar))
        blocks.push(`<div class="gram-subsec"><h5>${esc(t("gramCompare"))}</h5>${grammarArabicFlowHtml(L.compare_ar)}</div>`);
      return `<div class="gram-notes-stack">${blocks.join("")}</div>`;
    })();
    const notesWarn = notesHas && suspiciousText(notesPanelInner) ? "يوجد نص غير واضح/ناقص" : "";
    const notesPanel = notesHas
      ? `<div class="panel gram-sec glass-card">
        <h3 class="gram-sec-title">${esc("Common pitfalls")}
          ${notesWarn ? warnMark(notesWarn) : ""}
        </h3>
        <p class="gram-sec-kicker">${esc(t("gramSecNotes"))}</p>
        <div class="gram-sec-body">${notesPanelInner}</div>
      </div>`
      : "";

    // Special lesson: irregular verbs (no generic "stages" UI; show verb list + contextual practice)
    // isIrregular defined above (before tbl) for source-table Arabic augmentation

    // Lesson UI tabs (stored per lesson) — only tabs with real content
    if (!state.grammar.ui || typeof state.grammar.ui !== "object") state.grammar.ui = {};
    if (!state.grammar.ui[lessonId] || typeof state.grammar.ui[lessonId] !== "object") state.grammar.ui[lessonId] = {};
    const availableTabs = [
      { k: "quiz", label: hasQuiz ? t("gramSecQuiz") : null },
      { k: "table", label: hasTable ? t("gramSecTable") : null },
      { k: "rule", label: hasRule ? t("gramSecRule") : null },
      { k: "examples", label: hasExamples ? t("gramSecExamples") : null },
      { k: "notes", label: notesHas ? t("gramSecNotes") : null },
    ].filter((x) => x.label);

    const defaultTab = hasQuiz ? "quiz" : hasTable ? "table" : hasRule ? "rule" : hasExamples ? "examples" : "notes";
    const uiTab = state.grammar.ui[lessonId].tab;
    const curTab = availableTabs.some((x) => x.k === uiTab) ? uiTab : defaultTab;
    state.grammar.ui[lessonId].tab = curTab;
    saveState();

    const tabsHtml = `<div class="pillrow" style="gap:10px;flex-wrap:wrap;margin:10px 0 14px">
      ${availableTabs
        .map(
          (x) =>
            `<button type="button" class="pill ${curTab === x.k ? "on" : ""}" data-gtab="${esc(x.k)}">${esc(x.label)}</button>`,
        )
        .join("")}
    </div>`;

    let mainPanel = "";
    if (curTab === "rule") mainPanel = rulePanel;
    else if (curTab === "table") mainPanel = tablePanel || `<div class="panel"><p class="empty">${esc(t("gramEmptyCat"))}</p></div>`;
    else if (curTab === "examples") mainPanel = examplesPanel;
    else if (curTab === "notes") mainPanel = notesPanel;
    else mainPanel = `<div class="panel gram-sec"><h3 style="margin:0 0 10px;font-size:15px;font-weight:900">${esc(
      t("gramSecQuiz"),
    )}</h3><div class="gram-sec-body gram-quiz-block">${quizSection || `<p class="empty">${esc(t("emptyQuiz"))}</p>`}</div></div>`;

    if (isIrregular && curTab === "table") {
      // Irregular verbs view: "common" + clean cards + quiz (no deletion).
      const extractIrregular = () => {
        const items = [];
        const seen = new Set();
        const pushRow = (base, past, v3, meaning) => {
          const b = String(base || "").trim();
          if (!b) return;
          const key = b.toLowerCase();
          if (seen.has(key)) return;
          seen.add(key);
          items.push({ base: b, past: String(past || "").trim(), v3: String(v3 || "").trim(), meaning: String(meaning || "").trim() });
        };
        const fromTable = (T) => {
          if (!T || !Array.isArray(T.rows)) return;
          for (const r of T.rows) {
            if (!Array.isArray(r)) continue;
            const rawCells = r.map((c) => String(c || "").trim());
            const cells = rawCells.filter(Boolean);
            const w = (x) => /^[A-Za-z]+(?:'[A-Za-z]+)?$/.test(String(x || "").trim());
            // Many of our tables are: المعنى | V1 | V2 | V3
            if (cells.length >= 4 && w(cells[1]) && w(cells[2]) && w(cells[3])) {
              pushRow(cells[1], cells[2], cells[3], cells[0]);
              continue;
            }
            // Fallback 3-column style: V1 | V2 | V3
            if (cells.length >= 3 && w(cells[0]) && w(cells[1]) && w(cells[2])) {
              pushRow(cells[0], cells[1], cells[2], "");
              continue;
            }
            if (cells.length >= 1 && w(cells[0])) pushRow(cells[0], "", "");
          }
        };
        if (Array.isArray(L.tables)) L.tables.forEach(fromTable);
        else fromTable(L.table);
        items.sort((a, b) => a.base.localeCompare(b.base));
        return items;
      };

      // Sanity check: 52 unique verbs (V1) — IRR_APPROVED_MASTER
      const irrBaseSet = new Set(IRR_APPROVED_MASTER.map((x) => String(x.base).toLowerCase()));
      const irrOk = IRR_APPROVED_MASTER.length === 52 && irrBaseSet.size === 52;

      const list = IRR_APPROVED_MASTER.slice().sort((a, b) => String(a.base).localeCompare(String(b.base)));
      const byForm = new Map();
      for (const it of list) {
        [it.base, it.past, it.v3].filter(Boolean).forEach((f) => byForm.set(String(f).toLowerCase(), it));
      }

      const grammarSafeFind = (base) => list.find((x) => String(x.base).toLowerCase() === String(base).toLowerCase()) || null;
      // PDF-style grouping (Group 1 / Group 2)
      const g1 = list.filter((x) => x.group === 1);
      const g2 = list.filter((x) => x.group === 2);

      const letterMap = new Map();
      for (const it of list) {
        const L0 = String(it.base || "").trim().charAt(0).toUpperCase();
        if (!L0) continue;
        if (!letterMap.has(L0)) letterMap.set(L0, []);
        letterMap.get(L0).push(it);
      }
      const letters = [...letterMap.keys()].sort((a, b) => a.localeCompare(b));

      const fixCaps = (s) => {
        const v = String(s || "").trim();
        if (!v) return v;
        // Keep complex forms as-is (spaces, slashes, parentheses, hyphens)
        if (/[\s/()_-]/.test(v)) return v;
        if (/^[A-Z][a-z']+$/.test(v)) return v.charAt(0).toLowerCase() + v.slice(1);
        return v;
      };

      const mkCard = (it, badge) => {
        const top = badge ? `<div class="pillrow" style="margin:0 0 10px"><span class="chip" dir="ltr" style="font-weight:900">${esc(badge)}</span></div>` : "";
        const irrCell = (labelAr, enVal, arVal) => {
          const en = fixCaps(enVal) || "—";
          const ar = String(arVal || "").trim();
          return `<div>
            <div style="font-size:11px;color:var(--muted);font-weight:850" dir="rtl">${esc(labelAr)}</div>
            <div style="font-family:var(--irr-en);font-weight:950" dir="ltr">${esc(en)}</div>
            ${
              ar
                ? `<div style="margin-top:4px" dir="rtl"><span class="chip" style="font-size:12px;opacity:.92">${esc(ar)}</span></div>`
                : ""
            }
          </div>`;
        };
        const cols = `<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;align-items:start">
          ${irrCell("المضارع", it.base, it.meaning)}
          ${irrCell("الماضي", it.past, it.past_ar)}
          ${irrCell("التصريف الثالث", it.v3, it.v3_ar)}
        </div>`;
        return `<div class="panel" style="padding:14px 14px;border-radius:16px;background:color-mix(in srgb, var(--surface2) 90%, transparent);border:1px solid var(--border)">${top}${cols}</div>`;
      };

      const listHtml = letters
        .map((L0) => {
          const rows = (letterMap.get(L0) || []).map((it) => mkCard(it, "")).join("");
          return `<details class="voc-phase-details" open>
            <summary><span style="font-weight:950">${esc(L0)}</span> <span class="chip" dir="ltr">${esc(String((letterMap.get(L0) || []).length))}</span></summary>
            <div class="grid" data-irr-letter="${esc(L0)}" style="grid-template-columns:repeat(auto-fill, minmax(min(100%, 270px), 1fr));gap:12px">${rows}</div>
          </details>`;
        })
        .join("");

      // Table-first premium UI (no cards)
      if (!state.grammar.irregular || typeof state.grammar.irregular !== "object") state.grammar.irregular = {};
      if (!state.grammar.irregular.stageDone || typeof state.grammar.irregular.stageDone !== "object") state.grammar.irregular.stageDone = {};

      const stageItems = (s) => IRR_APPROVED_MASTER.filter((x) => x.stage === s);
      const curStage = clamp(Number(state.grammar.irregular.stage || 1) || 1, 1, 7);
      state.grammar.irregular.stage = curStage;
      saveState();

      const stageTableRow = (it) => {
        const base = fixCaps(it.base);
        const past = fixCaps(it.past);
        const v3 = fixCaps(it.v3);
        const m = String(it.meaning || "").trim();
        return `<tr data-irr-row>
          <td dir="ltr" style="font-family:var(--irr-en);font-weight:950">
            ${esc(base)}
            ${m ? `<div style="margin-top:4px" dir="rtl"><span class="chip" style="opacity:.92">${esc(m)}</span></div>` : ""}
          </td>
          <td dir="ltr" style="font-family:var(--irr-en);font-weight:950">
            ${esc(past || "—")}
            ${it.past_ar ? `<div style="margin-top:4px" dir="rtl"><span class="chip" style="opacity:.92">${esc(it.past_ar)}</span></div>` : ""}
          </td>
          <td dir="ltr" style="font-family:var(--irr-en);font-weight:950">
            ${esc(v3 || "—")}
            ${it.v3_ar ? `<div style="margin-top:4px" dir="rtl"><span class="chip" style="opacity:.92">${esc(it.v3_ar)}</span></div>` : ""}
          </td>
        </tr>`;
      };

      const stagePills = `<div class="pillrow" style="margin:0;gap:10px;flex-wrap:wrap">
        ${Array.from({ length: 7 }, (_, i) => i + 1)
          .map((s) => `<button type="button" class="pill ${s === curStage ? "on" : ""}" data-irr-stage="${esc(String(s))}">مرحلة ${esc(String(s))}</button>`)
          .join("")}
      </div>`;

      const stagePanel = `<div class="panel glass-card" style="margin-top:12px">
        <div class="pillrow" style="margin:0 0 10px;justify-content:space-between;gap:10px;flex-wrap:wrap">
          <div class="pillrow" style="margin:0;gap:10px;flex-wrap:wrap">
            <span class="chip" style="font-weight:950">مرحلة <span dir="ltr">${esc(String(curStage))}</span></span>
            <span class="chip" style="opacity:.9">المجموعة ${esc(curStage <= 5 ? "١" : "٢")}</span>
            <span class="chip" dir="ltr" style="font-weight:900">${esc(String(stageItems(curStage).length))}</span>
            <span class="chip" style="font-weight:900;${irrOk ? "" : "border-color:rgba(239,68,68,.5);color:var(--bad)"}">${esc(
              irrOk ? "✔︎ 52 فعل (معتمد)" : "تحذير: يوجد نقص/تكرار",
            )}</span>
          </div>
          <div class="pillrow" style="margin:0;gap:10px;flex-wrap:wrap">
            <button type="button" class="btn btn-sec" id="irrStageDoneBtn">${state.grammar.irregular.stageDone[String(curStage)] ? "تمت" : "علّم كـ تم"}</button>
            <button type="button" class="btn btn-primary" id="irrStageQuizBtn">اختبار المرحلة</button>
          </div>
        </div>
        ${stagePills}
        <div class="table-responsive" style="margin-top:12px">
          <table class="irr-prem-table">
            <thead>
              <tr>
                <th dir="rtl" style="font-family:var(--font)">المضارع</th>
                <th dir="rtl" style="font-family:var(--font)">الماضي</th>
                <th dir="rtl" style="font-family:var(--font)">التصريف الثالث</th>
              </tr>
            </thead>
            <tbody id="irrStageTbody">${stageItems(curStage).map(stageTableRow).join("")}</tbody>
          </table>
        </div>
      </div>`;

      const groupsHtml = stagePanel;

      const tableHtml = ``;

      mainPanel = `
        <div class="panel gram-sec glass-card">
          <h3 class="gram-sec-title">${esc("Irregular Verbs")}</h3>
          <p class="gram-sec-kicker">عرض حسب تقسيم الملف المعتمد + A–Z + كويز.</p>
          <label class="search" style="margin-top:12px">
            <input type="search" id="irrSearch" placeholder="ابحث عن فعل… (مثال: go / went)" autocomplete="off" dir="ltr"/>
          </label>
          <div class="pillrow" style="margin-top:12px;gap:10px;flex-wrap:wrap">
            <button type="button" class="pill on" id="irrTabCommon">المجموعات</button>
            <button type="button" class="pill" id="irrTabList">A–Z</button>
            <button type="button" class="pill" id="irrTabQuiz">كويز</button>
            <span class="chip" id="irrCount" dir="ltr" style="font-weight:900">${esc(String(list.length))}</span>
          </div>

          <div id="irrPaneCommon" style="margin-top:12px">
            ${groupsHtml}
          </div>

          <div id="irrPaneList" style="margin-top:12px;display:none">
            <div id="irrList">${listHtml || `<p class="empty">${esc(t("gramEmptyCat"))}</p>`}</div>
            ${tableHtml}
          </div>

          <div id="irrPaneQuiz" style="margin-top:12px;display:none">
            <div class="panel" style="background:color-mix(in srgb, var(--surface2) 88%, transparent);border:1px solid var(--border)">
              <div class="pillrow" style="margin-top:0;justify-content:space-between;gap:10px">
                <button type="button" class="btn btn-sec" id="irrPrev">${esc(t("prev"))}</button>
                <div class="chip" id="irrProg" dir="ltr" style="font-weight:900">1/1</div>
                <button type="button" class="btn btn-sec" id="irrNext">${esc(t("next"))}</button>
              </div>
              <div class="pillrow" style="margin-top:10px;gap:10px;flex-wrap:wrap;justify-content:flex-start">
                <button type="button" class="btn btn-sec" id="irrRetryQ" disabled>إعادة السؤال</button>
                <button type="button" class="btn btn-sec" id="irrReset">إعادة الكويز من جديد</button>
              </div>
              <div class="ar-text" id="irrPrompt" style="margin-top:12px;font-weight:900"></div>
              <div class="en-text" id="irrStem" dir="ltr" style="margin-top:8px;font-weight:950"></div>
              <div class="ar-text" id="irrStemAr" dir="rtl" style="margin-top:6px;font-weight:750;display:none"></div>
              <div class="pillrow" id="irrOpts" style="margin-top:12px;gap:10px;flex-direction:column;align-items:stretch"></div>
              <div class="panel" id="irrFb" style="margin-top:12px;display:none;padding:12px 14px;border-radius:12px;border:1px dashed color-mix(in srgb, var(--border) 75%, transparent);background:color-mix(in srgb, var(--surface) 78%, transparent)"></div>
            </div>
          </div>

          ${
            tablePanel
              ? `<details style="margin-top:12px" class="glass-card">
                  <summary style="cursor:pointer;font-weight:900">عرض الجداول الأصلية (المصدر)</summary>
                  <div style="margin-top:12px">${tbl}</div>
                </details>`
              : ""
          }
        </div>`;

    }

    v.innerHTML = `
      ${backBar(back)}
      <div class="hero gram-lesson-hero-wrap">
        ${breadcrumbHtml}
        <div class="gram-lesson-hero">
          <h2 class="gram-lesson-title-ar">${esc(L.title_ar)}</h2>
          <p class="gram-lesson-title-en" dir="ltr">${esc(L.title_en)}</p>
          ${
            topic.en
              ? `<div class="pillrow" style="margin-top:10px"><span class="chip" dir="ltr" style="font-weight:850">${esc(
                  topic.en,
                )}</span>${topic.ar ? `<span class="chip">${esc(topic.ar)}</span>` : ""}</div>`
              : ""
          }
          ${explainBlock}
        </div>
        <div class="gram-lesson-meta pillrow">
          <button type="button" class="pill ${favOn ? "on" : ""}" id="gramFav">${esc(t("gramFavorite"))}</button>
          ${doneOn ? `<span class="chip">${esc(t("gramCompleted"))}</span>` : ""}
        </div>
      </div>
      ${tabsHtml}
      <div class="gram-lesson-flow">${mainPanel}</div>`;

    v.querySelectorAll("[data-gtab]").forEach((b) => {
      b.addEventListener("click", () => {
        const k = b.getAttribute("data-gtab");
        if (!k) return;
        state.grammar.ui[lessonId].tab = k;
        saveState();
        render();
      });
    });

    wireGrammarLessonQuizTokens(v, L, st, qs, hasMultiQuiz);

    v.querySelectorAll("[data-speak]").forEach((btn) => {
      btn.onclick = () => speakEn(btn.getAttribute("data-speak"));
    });

    $("#gramFav").onclick = () => {
      state.grammar.fav[lessonId] = !state.grammar.fav[lessonId];
      saveState();
      render();
    };

    bindGrammarReviewOfferClicks(v);

    // Irregular verbs: wire list filter + quick quiz inside the Table tab.
    if (isIrregular && curTab === "table") {
      const all = IRR_APPROVED_MASTER.slice();

      const setPane = (k) => {
        const onCommon = k === "common";
        const onList = k === "list";
        const onQuiz = k === "quiz";
        $("#irrPaneCommon") && ($("#irrPaneCommon").style.display = onCommon ? "block" : "none");
        $("#irrPaneList") && ($("#irrPaneList").style.display = onList ? "block" : "none");
        $("#irrPaneQuiz") && ($("#irrPaneQuiz").style.display = onQuiz ? "block" : "none");
        $("#irrTabCommon")?.classList.toggle("on", onCommon);
        $("#irrTabList")?.classList.toggle("on", onList);
        $("#irrTabQuiz")?.classList.toggle("on", onQuiz);
      };
      $("#irrTabCommon") && ($("#irrTabCommon").onclick = () => setPane("common"));
      $("#irrTabList") && ($("#irrTabList").onclick = () => setPane("list"));
      $("#irrTabQuiz") && ($("#irrTabQuiz").onclick = () => {
        setPane("quiz");
        renderQ();
      });

      const applyFilter = () => {
        const q = String($("#irrSearch")?.value || "").trim().toLowerCase();
        let shown = 0;
        v.querySelectorAll("[data-irr-letter]").forEach((box) => {
          let any = false;
          box.querySelectorAll(".panel").forEach((row) => {
            const t = row.textContent.toLowerCase();
            const ok = !q || t.includes(q);
            row.style.display = ok ? "" : "none";
            if (ok) {
              any = true;
              shown++;
            }
          });
          const det = box.closest("details");
          if (det) det.style.display = any ? "" : "none";
        });
        // Also filter stage table (if present)
        const stBody = $("#irrStageTbody");
        if (stBody) {
          let shownRows = 0;
          stBody.querySelectorAll("[data-irr-row]").forEach((tr) => {
            const t = tr.textContent.toLowerCase();
            const ok = !q || t.includes(q);
            tr.style.display = ok ? "" : "none";
            if (ok) shownRows++;
          });
          if (q) shown = shownRows;
        }
        $("#irrCount") && ($("#irrCount").textContent = String(shown || 0));
      };
      $("#irrSearch")?.addEventListener("input", applyFilter);
      applyFilter();

      // Default pane (common)
      setPane("common");

      // Quick quiz: base -> past (or past->base if missing past)
      let irrQuizGroup = 0; // 0=all, 1=G1, 2=G2
      const mkQuiz = (group) => {
        const pool = all.filter((x) => x.base && (!group || x.group === group));
        const pastPool = pool.filter((x) => x.past);
        const qs = [];
        const uniq = (arr) => [...new Set(arr)];
        /** Always include `correct`; never slice a shuffled pool (correct could be dropped). */
        const fourChoices = (correct, distractorPool) => {
          const wrongPool = uniq(distractorPool.filter((x) => x && x !== correct));
          const k = Math.min(3, wrongPool.length);
          const picks = shuffle(wrongPool).slice(0, k);
          return shuffle([correct, ...picks]);
        };
        const pastIx = shuffle([...Array(pastPool.length).keys()]);
        for (let j = 0; j < Math.min(18, pastPool.length); j++) {
          const it = pastPool[pastIx[j]];
          const correct = it.past;
          const wrongs = pastPool.map((x) => x.past);
          const choices = fourChoices(correct, wrongs);
          qs.push({
            prompt_ar: "ما هو الماضي للفعل التالي؟",
            stem_en: it.base,
            stem_ar: String(it.meaning || "").trim(),
            choices_en: choices,
            answer_en: correct,
            explain_ar: `المضارع: ${it.base} (${it.meaning || "—"}) — الماضي: ${it.past} (${it.past_ar || "—"}) — التصريف الثالث: ${it.v3} (${it.v3_ar || "—"})`,
          });
        }
        // If very small, add reverse questions too
        if (qs.length < 8 && pastPool.length) {
          const revIx = shuffle([...Array(pastPool.length).keys()]);
          for (let j = 0; j < Math.min(12, pastPool.length); j++) {
            const it = pastPool[revIx[j]];
            const correct = it.base;
            const wrongs = pastPool.map((x) => x.base);
            const choices = fourChoices(correct, wrongs);
            qs.push({
              prompt_ar: "ما هو المضارع (الشكل الأول) لهذا الماضي؟",
              stem_en: it.past,
              stem_ar: String(it.past_ar || "").trim(),
              choices_en: choices,
              answer_en: correct,
              explain_ar: `الماضي: ${it.past} (${it.past_ar || "—"}) — المضارع: ${it.base} (${it.meaning || "—"}) — التصريف الثالث: ${it.v3} (${it.v3_ar || "—"})`,
            });
          }
        }
        return qs.slice(0, 20);
      };

      let quiz = mkQuiz(irrQuizGroup);
      let qi = 0;
      let picked = {};

      const rebuildQuiz = () => {
        quiz = mkQuiz(irrQuizGroup);
        qi = 0;
        picked = {};
        renderQ();
      };

      $("#irrReset") &&
        ($("#irrReset").onclick = () => {
          rebuildQuiz();
        });

      $("#irrRetryQ") &&
        ($("#irrRetryQ").onclick = () => {
          delete picked[qi];
          renderQ();
        });

      // Stage-based quiz & navigation (premium dashboard)
      const stageBtns = v.querySelectorAll("[data-irr-stage]");
      stageBtns.forEach((btn) => {
        btn.addEventListener("click", () => {
          const s = clamp(Number(btn.getAttribute("data-irr-stage")) || 1, 1, 7);
          if (!state.grammar.irregular || typeof state.grammar.irregular !== "object") state.grammar.irregular = {};
          state.grammar.irregular.stage = s;
          saveState();
          render();
        });
      });

      $("#irrStageDoneBtn") &&
        ($("#irrStageDoneBtn").onclick = () => {
          if (!state.grammar.irregular || typeof state.grammar.irregular !== "object") state.grammar.irregular = {};
          if (!state.grammar.irregular.stageDone || typeof state.grammar.irregular.stageDone !== "object") state.grammar.irregular.stageDone = {};
          const s = clamp(Number(state.grammar.irregular.stage || 1) || 1, 1, 7);
          state.grammar.irregular.stageDone[String(s)] = !state.grammar.irregular.stageDone[String(s)];
          saveState();
          render();
        });

      $("#irrStageQuizBtn") &&
        ($("#irrStageQuizBtn").onclick = () => {
          const s = clamp(Number(state.grammar.irregular?.stage || 1) || 1, 1, 7);
          irrQuizGroup = s <= 5 ? 1 : 2;
          // filter quiz pool by stage
          const stageOnly = all.filter((x) => x.stage === s);
          const prevAll = all.slice();
          all.length = 0;
          stageOnly.forEach((x) => all.push(x));
          setPane("quiz");
          rebuildQuiz();
          // restore list so search and other UI remain correct
          all.length = 0;
          prevAll.forEach((x) => all.push(x));
        });

      // (Favorites UI disabled in table-first view)

      function renderQ() {
        if (!$("#irrPaneQuiz")) return;
        if (!quiz.length) {
          $("#irrPaneQuiz").innerHTML = `<p class="empty">لا توجد بيانات كافية لبناء كويز من الجداول الحالية.</p>`;
          return;
        }
        qi = clamp(qi, 0, quiz.length - 1);
        const q = quiz[qi];
        $("#irrProg").textContent = `${qi + 1}/${quiz.length}`;
        $("#irrPrev").disabled = qi <= 0;
        $("#irrNext").disabled = qi >= quiz.length - 1;
        $("#irrPrompt").textContent = q.prompt_ar || "";
        $("#irrStem").textContent = q.stem_en || "";
        const sar = $("#irrStemAr");
        if (sar) {
          const tx = String(q.stem_ar || "").trim();
          sar.textContent = tx;
          sar.style.display = tx ? "block" : "none";
        }

        const lock = typeof picked[qi] === "string";
        const ans = q.answer_en;
        $("#irrOpts").innerHTML = (q.choices_en || [])
          .map((c) => {
            const isAns = lock && c === ans;
            const cls = isAns ? "btn btn-primary" : "btn btn-sec";
            return `<button type="button" class="${cls}" data-irr-pick="${esc(c)}" ${lock ? "disabled" : ""} style="justify-content:flex-start;direction:ltr;text-align:left">${esc(
              c,
            )}</button>`;
          })
          .join("");

        const fb = $("#irrFb");
        fb.style.display = lock ? "block" : "none";
        if (lock) {
          const ok = picked[qi] === ans;
          fb.innerHTML = `<div class="ar-text" style="font-weight:950;color:${ok ? "var(--ok)" : "var(--bad)"}">${esc(
            ok ? "صحيح" : "خطأ",
          )}</div><div class="en-text" dir="ltr" style="margin-top:6px;font-weight:950;font-family:var(--irr-en)">${esc(
            "الإجابة الصحيحة: " + ans,
          )}</div>${q.explain_ar ? `<div class="ar-text" style="margin-top:8px">${esc(q.explain_ar)}</div>` : ""}`;
        }

        $("#irrOpts").querySelectorAll("[data-irr-pick]").forEach((b) => {
          b.addEventListener("click", () => {
            const c = b.getAttribute("data-irr-pick");
            if (!c) return;
            picked[qi] = c;
            renderQ();
          });
        });

        const retryBtn = $("#irrRetryQ");
        if (retryBtn) retryBtn.disabled = !lock;
      }

      $("#irrPrev") && ($("#irrPrev").onclick = () => {
        qi = Math.max(0, qi - 1);
        renderQ();
      });
      $("#irrNext") && ($("#irrNext").onclick = () => {
        qi = Math.min(quiz.length - 1, qi + 1);
        renderQ();
      });
    }

    const stNav = grammarLessonQuiz[lessonId];
    // Multi-stage quiz tab (stage/final) controls
    v.querySelectorAll("[data-gqtab]").forEach((btn) => {
      btn.addEventListener("click", () => {
        if (!stNav.ui || typeof stNav.ui !== "object") stNav.ui = { mode: "stage", stage: 0 };
        const mode = btn.getAttribute("data-gqtab");
        if (mode === "final") {
          stNav.ui.mode = "final";
        } else {
          stNav.ui.mode = "stage";
          const si = Number(btn.getAttribute("data-stage"));
          if (Number.isFinite(si)) stNav.ui.stage = si;
        }
        render();
      });
    });
    $("#gramExPrev")?.addEventListener("click", () => {
      if (stNav.exPos > 0) {
        stNav.exPos--;
        render();
      }
    });
    $("#gramExNext")?.addEventListener("click", () => {
      const maxEx = (L.examples || []).length - 1;
      if (maxEx >= 0 && stNav.exPos < maxEx) {
        stNav.exPos++;
        render();
      }
    });
    if (!hasMultiQuiz) {
      $("#gramQuizPrev")?.addEventListener("click", () => {
        if (stNav.quizPos > 0) {
          stNav.quizPos--;
          render();
        }
      });
      $("#gramQuizNext")?.addEventListener("click", () => {
        if (qs.length && stNav.quizPos < qs.length - 1) {
          stNav.quizPos++;
          render();
        }
      });
    } else {
      L.quizStages.forEach((stage, si) => {
        const n = (stage.quiz || []).length;
        $(`#gqs${si}-quiz-prev`)?.addEventListener("click", () => {
          if (stNav.stages[si].quizPos > 0) {
            stNav.stages[si].quizPos--;
            render();
          }
        });
        $(`#gqs${si}-quiz-next`)?.addEventListener("click", () => {
          if (n && stNav.stages[si].quizPos < n - 1) {
            stNav.stages[si].quizPos++;
            render();
          }
        });
      });
      const nf = (L.quizComprehensive || []).length;
      $("#gqf-quiz-prev")?.addEventListener("click", () => {
        if (stNav.final.quizPos > 0) {
          stNav.final.quizPos--;
          render();
        }
      });
      $("#gqf-quiz-next")?.addEventListener("click", () => {
        if (nf && stNav.final.quizPos < nf - 1) {
          stNav.final.quizPos++;
          render();
        }
      });
    }

    v.querySelectorAll(".gram-qblock .opt").forEach((btn) => {
      btn.onclick = () => {
        const qix = parseInt(btn.getAttribute("data-qix"), 10);
        const oix = parseInt(btn.getAttribute("data-oix"), 10);
        const tag = btn.getAttribute("data-gram-quiz") || "legacy";
        const cur = grammarLessonQuiz[lessonId];
        let item;
        if (tag === "final") {
          item = L.quizComprehensive[qix];
          if (cur.final.picks[qix] !== null && cur.final.picks[qix] !== undefined) return;
          cur.final.picks[qix] = oix;
        } else if (tag.startsWith("stage:")) {
          const si = parseInt(tag.slice("stage:".length), 10);
          item = L.quizStages[si].quiz[qix];
          if (cur.stages[si].picks[qix] !== null && cur.stages[si].picks[qix] !== undefined) return;
          cur.stages[si].picks[qix] = oix;
        } else {
          item = qs[qix];
          if (!item || cur.picks[qix] !== null && cur.picks[qix] !== undefined) return;
          cur.picks[qix] = oix;
        }
        const isCorrect = oix === item.correct;
        if (grammarLessonComplete(lessonId)) grammarMarkLessonDone(lessonId);
        saveState();
        beep(isCorrect);
        if (isCorrect) {
          setTimeout(() => {
            if (tag === "final") {
              const nf = (L.quizComprehensive || []).length;
              if (nf && cur.final.quizPos < nf - 1) cur.final.quizPos++;
            } else if (tag.startsWith("stage:")) {
              const si = parseInt(tag.slice("stage:".length), 10);
              const n = (L.quizStages[si].quiz || []).length;
              if (n && cur.stages[si].quizPos < n - 1) cur.stages[si].quizPos++;
            } else if (qs.length && cur.quizPos < qs.length - 1) {
              cur.quizPos++;
            }
            saveState();
            render();
          }, 420);
        }
        render();
      };
    });

    $("[data-back]")?.addEventListener("click", () => (location.hash = back));
  }

  function renderGrammarFinal() {
    const v = $("#view");
    const unitCatId = grammarSeg.unitQuiz || "";
    const isUnit = !!unitCatId;
    const poolMaster = isUnit ? grammarQuizPoolForCategory(unitCatId) : grammarQuizPoolAll;
    const catMeta = isUnit ? grammarCategoryById(unitCatId) : null;
    const examLabel = isUnit
      ? lang === "en" && catMeta && catMeta.title_en && String(catMeta.title_en).trim()
        ? String(catMeta.title_en).trim()
        : catMeta && catMeta.title_ar
          ? catMeta.title_ar
          : t("gramUnitQuizTitle")
      : t("gramFinalBtn");

    const inFinalReview = grammarSeg.final && grammarSeg.review;
    const inUnitReview = !!(grammarSeg.unitQuiz && grammarSeg.unitReview);
    const inAnyReview = inFinalReview || inUnitReview;

    if (inAnyReview) {
      if (!grammarFinalSession || grammarFinalSession.phase !== "done" || !grammarFinalSession.results) {
        location.hash = inUnitReview ? "#/grammar/quiz/" + encodeURIComponent(unitCatId) : "#/grammar/final";
        return;
      }
      const R = grammarFinalSession.results;
      const rows = R.items
        .map((it, i) => {
          const ok = it.pick === it.correct;
          return `<div class="qrow">
          <div class="t">${i + 1}. ${esc(it.question_en)}</div>
          <div class="m">${ok ? "✓" : "✗"} · ${esc(it.lessonTitle || "")}</div>
          <div style="font-size:13px;margin-top:8px;color:var(--muted)">${esc(t("correctShort"))}: ${esc(it.options[it.correct])}</div>
        </div>`;
        })
        .join("");
      v.innerHTML = `
        ${backBar("#/grammar/tests")}
        <div class="hero">
          <h2>${esc(t("gramFinalReview"))}</h2>
          <p class="lead">${esc(R.score + "/" + R.total)} · ${R.pct}%</p>
        </div>
        <div class="rowlist">${rows}</div>
        <div class="toolbar">
          <button type="button" class="btn btn-primary" id="gramRetakeBtn">${esc(t("gramRetake"))}</button>
        </div>`;
      $("#gramRetakeBtn").onclick = () => {
        grammarFinalSession = null;
        location.hash = inUnitReview ? "#/grammar/quiz/" + encodeURIComponent(unitCatId) : "#/grammar/final";
      };
      $("[data-back]")?.addEventListener("click", () => (location.hash = "#/grammar/tests"));
      return;
    }

    if (!grammarFinalSession) {
      if (!poolMaster.length) {
        v.innerHTML = `
        ${backBar("#/grammar/tests")}
        <div class="hero">
          <h2>${esc(isUnit ? t("gramUnitQuizTitle") : t("gramFinalBtn"))}</h2>
          <p class="lead">${esc(isUnit ? t("gramUnitNoQuestions") : t("gramFinalNoPool"))}</p>
        </div>`;
        $("[data-back]")?.addEventListener("click", () => (location.hash = "#/grammar/tests"));
        return;
      }
      const introLead = isUnit
        ? (lang === "ar"
            ? `أسئلة عشوائية من دروس هذه الوحدة (حتى ٥٠ سؤالًا). المتاح: ${poolMaster.length} سؤالًا.`
            : `Random questions from this unit (up to 50). Available: ${poolMaster.length}.`)
        : lang === "ar"
          ? "٥٠ سؤالًا عشوائيًا من جميع الدروس"
          : "50 random questions from all lessons";
      v.innerHTML = `
        ${backBar("#/grammar/tests")}
        <div class="hero">
          <h2>${esc(examLabel)}</h2>
          <p class="lead">${esc(introLead)}</p>
          <label style="display:flex;gap:10px;align-items:center;margin-top:14px;font-weight:650">
            <input type="checkbox" id="gramTimerCk"/> ${esc(t("gramTimerOpt"))}
          </label>
          <button type="button" class="btn btn-primary" style="margin-top:16px" id="gramStartFinal">${esc(t("gramStartFinal"))}</button>
        </div>`;
      $("#gramStartFinal").onclick = () => {
        const useTimer = $("#gramTimerCk").checked;
        const pool = shuffle(poolMaster.slice());
        const n = Math.min(50, pool.length);
        const items = pool.slice(0, n);
        const timerEnd = useTimer ? Date.now() + 10 * 60 * 1000 : 0;
        grammarFinalSession = {
          phase: "run",
          items,
          picks: Array(n).fill(null),
          pos: 0,
          useTimer,
          timerEnd,
          intervalId: null,
        };
        if (useTimer && timerEnd) {
          grammarFinalSession.intervalId = setInterval(() => {
            const left = Math.max(0, grammarFinalSession.timerEnd - Date.now());
            const el = $("#gramFinalTimerDisp");
            if (el) {
              const mm = Math.floor(left / 60000);
              const ss = Math.floor((left % 60000) / 1000);
              el.textContent = `${mm}:${String(ss).padStart(2, "0")}`;
            }
            if (left <= 0) {
              grammarFinalizeResults();
              render();
            }
          }, 400);
        }
        render();
      };
      $("[data-back]")?.addEventListener("click", () => (location.hash = "#/grammar/tests"));
      return;
    }

    if (grammarFinalSession.phase === "run") {
      const S = grammarFinalSession;
      const total = S.items.length;
      const cur = S.items[S.pos];
      const lesson = grammarLessonsById[cur.lessonId];
      const lessonTitle = lesson ? lesson.title_en : "";
      const picked = S.picks[S.pos];
      const locked = picked !== null && picked !== undefined;
      const okAns = locked && picked === cur.correct;
      const deepWrong = locked && !okAns ? grammarDeepFeedbackHtml(cur, picked) : "";
      const gramRevExam =
        locked && !okAns
          ? grammarReviewOfferHtml(
              cur.lessonId || "_",
              S.pos,
              isUnit ? `finalUnit:${unitCatId}` : "finalAll"
            )
          : "";
      const letters = ["A", "B", "C"];
      const opts = cur.options
        .map((op, oi) => {
          let cls = "opt";
          if (locked) cls += oi === cur.correct ? " correct" : picked === oi ? " wrong" : "";
          return `<button type="button" class="${cls}" data-fo="${oi}" ${locked ? "disabled" : ""}><span class="L">${letters[oi]}</span><span class="txt gram-opt-tok" dir="ltr" id="gramFinal-opt-${oi}"></span></button>`;
        })
        .join("");

      const timeRow =
        S.useTimer && S.timerEnd ? `<div class="gram-toolbar"><span class="gram-final-timer" id="gramFinalTimerDisp"></span></div>` : "";

      const nFinalAns = S.picks.filter((x) => x !== null && x !== undefined).length;

      v.innerHTML = `
        ${backBar("#/grammar/tests")}
        ${timeRow}
        <div class="panel">
          <div class="qnum">${esc(examLabel)} · ${S.pos + 1} / ${total}</div>
          <p class="gram-final-remain">${esc(fmtAnswerRemainLine("quizAnswerRemainLine", nFinalAns, total))}</p>
          <p class="qtext gram-q-line" dir="ltr"><span id="gramFinalQTok" class="gram-q-tokens-host"></span></p>
          <p style="font-size:12px;color:var(--muted);font-weight:650">${esc(lessonTitle)}</p>
          <div class="opts" id="gramFinalOpts">${opts}</div>
          ${
            locked
              ? `<div class="learn" id="gramFinalLearn">
            <div class="lblock"><h4>${esc(t("gramWhy"))}</h4><div class="ar">${esc(cur.why_ar)}</div></div>
            <div class="lblock"><h4>${esc(t("gramUsedRule"))}</h4><div class="ar">${esc(cur.rule_ar)}</div></div>
            ${deepWrong}
            ${gramRevExam}
          </div>`
              : ""
          }
          <div class="pillrow" style="margin-top:16px">
            <button type="button" class="btn btn-sec" id="gramFinalPrev" ${S.pos ? "" : "disabled"}>${esc(t("prev"))}</button>
            <button type="button" class="btn btn-primary" id="gramFinalNext">${esc(t("next"))}</button>
          </div>
        </div>`;

      wireGrammarExamTokens(v, cur, "gramFinalQTok", "gramFinal-opt-");
      bindGrammarReviewOfferClicks(v);

      if (S.useTimer && S.timerEnd) {
        const el = $("#gramFinalTimerDisp");
        if (el) {
          const left = Math.max(0, S.timerEnd - Date.now());
          const mm = Math.floor(left / 60000);
          const ss = Math.floor((left % 60000) / 1000);
          el.textContent = `${mm}:${String(ss).padStart(2, "0")}`;
        }
      }

      $("#gramFinalOpts").querySelectorAll(".opt").forEach((btn) => {
        btn.onclick = () => {
          if (locked) return;
          const oi = parseInt(btn.getAttribute("data-fo"), 10);
          S.picks[S.pos] = oi;
          const isCorrect = oi === cur.correct;
          saveState();
          beep(isCorrect);
          if (isCorrect) {
            setTimeout(() => {
              if (S.pos < total - 1) {
                S.pos++;
                saveState();
                render();
              } else {
                grammarFinalizeResults();
                render();
              }
            }, 420);
          }
          render();
        };
      });

      $("#gramFinalPrev").onclick = () => {
        if (S.pos > 0) {
          S.pos--;
          render();
        }
      };

      $("#gramFinalNext").onclick = () => {
        if (!locked) {
          toast(t("pickAnswer"), "bad");
          return;
        }
        if (S.pos < total - 1) {
          S.pos++;
          render();
        } else {
          grammarFinalizeResults();
          render();
        }
      };

      $("[data-back]")?.addEventListener("click", () => (location.hash = "#/grammar/tests"));
      return;
    }

    if (grammarFinalSession.phase === "done") {
      const R = grammarFinalSession.results;
      v.innerHTML = `
        ${backBar("#/grammar/tests")}
        <div class="hero">
          <h2>${esc(t("gramScore"))}</h2>
          <p class="lead">${esc(R.score + "/" + R.total)} — ${esc(t("gramPct"))}: ${R.pct}%</p>
        </div>
        <div class="kpis">
          <div class="kpi"><div class="v">${esc(String(R.pct))}%</div><div class="l">${esc(t("gramPct"))}</div></div>
          <div class="kpi"><div class="v">${esc(String(R.score))}</div><div class="l">${esc(t("correctShort"))}</div></div>
          <div class="kpi"><div class="v">${esc(String(R.total))}</div><div class="l">${esc(t("solved"))}</div></div>
        </div>
        <div class="toolbar">
          <button type="button" class="btn btn-primary" id="gramRevBtn">${esc(t("gramFinalReview"))}</button>
          <button type="button" class="btn btn-sec" id="gramRetake2">${esc(t("gramRetake"))}</button>
        </div>`;
      $("#gramRevBtn").onclick = () => {
        location.hash = isUnit
          ? "#/grammar/quiz/" + encodeURIComponent(unitCatId) + "/review"
          : "#/grammar/final/review";
      };
      $("#gramRetake2").onclick = () => {
        grammarFinalSession = null;
        location.hash = isUnit ? "#/grammar/quiz/" + encodeURIComponent(unitCatId) : "#/grammar/final";
      };
      $("[data-back]")?.addEventListener("click", () => (location.hash = "#/grammar/tests"));
      return;
    }
  }

  function grammarAuditReadJson(elId) {
    if (typeof __GRAMMAR_AUDIT_EMBED__ !== "undefined" && __GRAMMAR_AUDIT_EMBED__ && Object.prototype.hasOwnProperty.call(__GRAMMAR_AUDIT_EMBED__, elId)) {
      return __GRAMMAR_AUDIT_EMBED__[elId];
    }
    try {
      const el = document.getElementById(elId);
      if (!el || !String(el.textContent || "").trim()) return null;
      return JSON.parse(el.textContent);
    } catch (_) {
      return null;
    }
  }

  /** دوري (وحدات 1–8) + ذاتي (مستقل)، بدون تكرار نفس السؤال الإنجليزي — يُحمَّل من blended_unique_quiz.json */
  function grammarBlendedPoolItems() {
    const data = grammarAuditReadJson("blended-unique-quiz-json");
    const raw = data && Array.isArray(data.items) ? data.items : [];
    return raw.map((it) => ({
      lessonId: it.lessonId,
      question_en: it.question_en,
      options: it.options,
      correct: it.correct,
      why_ar: it.why_ar,
      rule_ar: it.rule_ar,
    }));
  }

