  function renderVocabBrowse(all) {
    const needle = vocabFilter.trim().toLowerCase();
    const matchRow = (r) =>
      !needle || r.en.toLowerCase().includes(needle) || r.ar.includes(needle);
    const keyForRow = (r) => String(r?.en || "").trim().toLowerCase();
    const isKnown = (r) => {
      const k = keyForRow(r);
      return !!(k && state.vocabKnown && state.vocabKnown[k]);
    };

    const eligible = vocabQuizEligible(all);
    const byPhase = {};
    for (const pid of VOCAB_PHASE_ORDER) byPhase[pid] = [];
    for (const r of eligible) {
      const pid = vocabPhaseIdForRow(r);
      if (!byPhase[pid]) byPhase[pid] = [];
      byPhase[pid].push(r);
    }

    const mount = $("#vocBrowseMount");
    if (!mount) return;
    mount.innerHTML = `
      <label class="search" style="margin-top:4px;display:flex"><input type="search" id="vq" placeholder="${esc(t("vocabSearch"))}" value="${esc(vocabFilter)}"/></label>
      <div class="voc-browse-tools">
        <button type="button" class="btn btn-sec" id="vocOnlyUnknown" aria-pressed="${state.vocabShowUnknownOnly ? "true" : "false"}">${esc(
          state.vocabShowUnknownOnly ? "عرض الكل" : "غير المفهومة فقط"
        )}</button>
        <button type="button" class="btn btn-sec" id="vocClearKnown">${esc("مسح كل الصحّات")}</button>
      </div>
      <div class="panel" id="vlist" style="margin-top:14px"></div>`;
    $("#vq").addEventListener("input", (e) => {
      vocabFilter = e.target.value;
      renderVocabHub();
    });
    $("#vocOnlyUnknown").addEventListener("click", () => {
      state.vocabShowUnknownOnly = !state.vocabShowUnknownOnly;
      saveState();
      renderVocabHub();
    });
    $("#vocClearKnown").addEventListener("click", () => {
      state.vocabKnown = {};
      saveState();
      renderVocabHub();
    });
    const box = $("#vlist");

    const sections = VOCAB_PHASE_ORDER.map((pid) => {
      const rows = (byPhase[pid] || [])
        .filter(matchRow)
        .filter((r) => (state.vocabShowUnknownOnly ? !isKnown(r) : true));
      if (!rows.length) return "";
      const title = vocabPhaseDisplayTitle(pid);
      const openOn = state.vocabPhaseOpen && state.vocabPhaseOpen[pid] !== undefined ? !!state.vocabPhaseOpen[pid] : true;
      const inner = `
        <div class="voc-hub-wrap">
          <div class="voc-hub-head"><span>${esc(t("vocColWord"))}</span><span>${esc(t("vocColMean"))}</span><span style="text-align:end">${esc(t("vocSource"))}</span><span style="text-align:end">${esc("تم")}</span></div>
          <div class="voc-hub-body">
            ${rows
              .map(
                (r) => {
                  const k = keyForRow(r);
                  const on = isKnown(r);
                  return `<div class="voc-hub-row" data-vk="${esc(k)}">
                    <span class="w-en">${esc(r.en)}</span>
                    <span class="w-ar">${esc(r.ar)}</span>
                    <span class="voc-tag ${r.isBank ? "bank" : "auto"}">${esc(r.isBank ? t("vocLegendBank") : t("vocLegendAuto"))}</span>
                    <button type="button" class="voc-known-btn ${on ? "on" : ""}" data-vk="${esc(k)}" aria-pressed="${on ? "true" : "false"}">${esc(on ? "✓" : "تم")}</button>
                  </div>`;
                }
              )
              .join("")}
          </div>
        </div>`;
      return `<details class="voc-phase-details"${openOn ? " open" : ""} data-vpid="${esc(pid)}"><summary class="voc-phase-sum"><span>${esc(
        title,
      )}</span><span class="voc-phase-count">${rows.length}</span></summary>${inner}</details>`;
    }).join("");

    if (!eligible.length) {
      box.innerHTML = `<div class="empty">${esc(t("vocEmpty"))}</div>`;
    } else if (!sections.trim()) {
      box.innerHTML = `<div class="empty">${esc(t("vocabNoResults"))}</div>`;
    } else {
      box.innerHTML = sections;
    }

    // Toggle “known / understood” per word
    box.querySelectorAll("[data-vk].voc-known-btn").forEach((btn) => {
      btn.addEventListener("click", () => {
        const k = String(btn.getAttribute("data-vk") || "").trim().toLowerCase();
        if (!k) return;
        if (!state.vocabKnown || typeof state.vocabKnown !== "object") state.vocabKnown = {};
        state.vocabKnown[k] = !state.vocabKnown[k];
        saveState();
        renderVocabHub();
      });
    });

    // Persist open/close state per phase so it doesn't collapse on rerender
    box.querySelectorAll("details.voc-phase-details[data-vpid]").forEach((d) => {
      d.addEventListener("toggle", () => {
        const pid = d.getAttribute("data-vpid");
        if (!pid) return;
        if (!state.vocabPhaseOpen || typeof state.vocabPhaseOpen !== "object") state.vocabPhaseOpen = {};
        state.vocabPhaseOpen[pid] = !!d.open;
        saveState();
      });
    });
  }

  function renderVocabQuizUi(all) {
    const main = $("#vocQuizArea") || $("#vocMain");
    const effPhase = vocabQuizMode === "allWords" ? "all" : vocabQuizPhase;
    const pool = vocQ.pool.length ? vocQ.pool : vocabRowsForPhaseFilter(all, effPhase);
    if (pool.length < 2) {
      main.innerHTML = `<div class="panel"><p class="empty">${esc(t("vocQuizTooFew"))}</p></div>`;
      return;
    }
    const totalR = vocQ.order.length;
    const finished = totalR > 0 && vocQ.pos >= totalR;
    if (finished) {
      main.innerHTML = `
        <div class="voc-quiz-card">
          ${vocQ.phaseKey && vocQ.phaseKey !== "all" ? `<p class="voc-quiz-prompt" style="margin-bottom:8px">${esc(t("vocQuizPhaseBadge"))}: ${esc(vocabPhaseDisplayTitle(vocQ.phaseKey))}</p>` : ""}
          <p class="voc-quiz-sum" style="text-align:center;margin-bottom:16px">${esc(t("vocQuizDone"))}</p>
          <p class="voc-quiz-sum" style="text-align:center;font-size:22px">${esc(t("vocQuizResult"))} <b>${vocQ.score}</b> / <b>${totalR}</b></p>
          <div style="margin-top:20px;text-align:center">
            <button type="button" class="btn btn-primary" id="vocAgain">${esc(t("vocQuizAgain"))}</button>
          </div>
        </div>`;
      $("#vocAgain").onclick = () => startVocabQuizRound(all);
      return;
    }
    const pi = vocQ.order[vocQ.pos];
    const row = vocQ.pool[pi];
    const n = vocQ.pos + 1;
    const vocAnsweredSoFar = vocQ.pos + (vocQ.locked ? 1 : 0);
    ensureStateReviews();
    const vk = String(row.en || "").trim().toLowerCase();
    const vocAlready = vk && state.vocabReview.includes(vk);
    const wrongPanelHtml = vocQ.wrongPick
      ? `<div class="voc-wrong-panel quiz-wrong-explain" style="margin-top:14px">
          <p>${esc(t("vocQuizCorrectWas"))}: <strong>${esc(row.ar)}</strong></p>
          ${
            vocAlready
              ? `<p class="home-tool-k" style="margin:10px 0 0">${esc(t("vocQuizInReview"))}</p>`
              : `<button type="button" class="btn btn-sec" id="vocAddRev">${esc(t("vocQuizAddReview"))}</button>`
          }
        </div>`
      : "";
    main.innerHTML = `
      <div class="voc-quiz-card">
        <div class="voc-quiz-foot" style="margin-top:0;margin-bottom:8px">
          ${vocQ.phaseKey && vocQ.phaseKey !== "all" ? `<span class="chip">${esc(t("vocQuizPhaseBadge"))}: ${esc(vocabPhaseDisplayTitle(vocQ.phaseKey))}</span>` : ""}
          <span class="chip">${esc(t("vocQuizProgress"))} ${n} / ${totalR}</span>
          <span class="chip">${esc(t("vocQuizResult"))} ${vocQ.score}</span>
        </div>
        <p class="voc-quiz-stats">${esc(fmtAnswerRemainLine("quizAnswerRemainLine", vocAnsweredSoFar, totalR))}</p>
        <p class="voc-quiz-prompt">${esc(t("vocQuizPrompt"))}</p>
        <div class="voc-quiz-word">${esc(row.en)}</div>
        <div class="voc-quiz-opts" id="vocOpts"></div>
        ${wrongPanelHtml}
        <div class="voc-quiz-foot">
          <span></span>
          <button type="button" class="btn btn-primary" id="vocNext" style="visibility:${vocQ.locked ? "visible" : "hidden"}">${esc(t("vocQuizNext"))}</button>
        </div>
      </div>`;
    const ox = $("#vocOpts");
    vocQ.opts.forEach((text, i) => {
      const b = document.createElement("button");
      b.type = "button";
      b.className = "opt";
      b.textContent = text;
      b.disabled = vocQ.locked;
      b.onclick = () => {
        if (vocQ.locked) return;
        vocQ.locked = true;
        const ok = i === vocQ.correctIdx;
        if (ok) vocQ.score++;
        beep(ok);
        ox.querySelectorAll("button").forEach((btn, j) => {
          btn.disabled = true;
          if (j === vocQ.correctIdx) btn.classList.add("correct");
          else if (j === i && !ok) btn.classList.add("wrong");
        });
        if (ok) {
          $("#vocNext").style.visibility = "hidden";
          setTimeout(() => {
            vocQ.pos++;
            vocQ.locked = false;
            vocQ.wrongPick = false;
            if (vocQ.pos >= vocQ.order.length) {
              renderVocabQuizUi(all);
              return;
            }
            const nextPi = vocQ.order[vocQ.pos];
            const mc = buildArMc(vocQ.pool, nextPi);
            vocQ.opts = mc.opts;
            vocQ.correctIdx = mc.correctIdx;
            renderVocabQuizUi(all);
          }, 420);
        } else {
          vocQ.wrongPick = true;
          $("#vocNext").style.visibility = "visible";
          renderVocabQuizUi(all);
        }
      };
      ox.appendChild(b);
    });
    $("#vocAddRev")?.addEventListener("click", () => {
      addVocabReviewWord(row.en);
      toast(t("vocQuizAddedReview"), "ok");
      renderVocabHub();
    });
    $("#vocNext").onclick = () => {
      vocQ.wrongPick = false;
      vocQ.pos++;
      vocQ.locked = false;
      if (vocQ.pos >= vocQ.order.length) {
        renderVocabQuizUi(all);
        return;
      }
      const nextPi = vocQ.order[vocQ.pos];
      const mc = buildArMc(vocQ.pool, nextPi);
      vocQ.opts = mc.opts;
      vocQ.correctIdx = mc.correctIdx;
      renderVocabQuizUi(all);
    };
  }

  function startVocabQuizRound(all) {
    const phaseKey = vocabQuizMode === "allWords" ? "all" : vocabQuizPhase;
    const pool = vocabRowsForPhaseFilter(all, phaseKey);
    if (pool.length < 2) {
      toast(t("vocQuizTooFew"), "bad");
      return;
    }
    vocQ.pool = pool;
    vocQ.phaseKey = phaseKey;
    vocQ.order = shuffle(pool.map((_, i) => i));
    vocQ.pos = 0;
    vocQ.score = 0;
    vocQ.locked = false;
    vocQ.wrongPick = false;
    const mc = buildArMc(pool, vocQ.order[0]);
    vocQ.opts = mc.opts;
    vocQ.correctIdx = mc.correctIdx;
    renderVocabQuizUi(all);
  }

